head.b:skin:
  :root {
    --white:    #ffffff;
    --off:      #f8f8f6;
    --ink:      #0a0a0a;
    --mid:      #525250;
    --muted:    #888884;
    --border:   #e6e6e3;
    --accent:   #1a1aff;
    --red:      #ff3a2d;
    --green:    #00c48c;
    --radius:   6px;
    --shadow:   0 2px 20px rgba(0,0,0,0.06);
    --shadow-h: 0 8px 40px rgba(0,0,0,0.11);
    --nav-h:    60px;
  }

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  html { scroll-behavior: smooth; }
  body {
    background: var(--white);
    color: var(--ink);
    font-family: 'DM Sans', sans-serif;
    font-size: 16px;
    line-height: 1.7;
    overflow-x: hidden;
    -webkit-font-smoothing: antialiased;
  }
  a { text-decoration: none; color: inherit; }
  img { max-width: 100%; height: auto; display: block; }
  button { font-family: inherit; cursor: pointer; }

  :focus-visible {
    outline: 2px solid var(--accent);
    outline-offset: 3px;
    border-radius: 3px;
  }

  ::-webkit-scrollbar { width: 3px; }
  ::-webkit-scrollbar-track { background: var(--off); }
  ::-webkit-scrollbar-thumb { background: var(--accent); border-radius: 99px; }

  .dwj-wrap {
    width: 100%;
    max-width: 1160px;
    margin: 0 auto;
    padding: 0 20px;
  }

  /* NAVBAR */
  .dwj-nav {
    position: fixed; top: 0; left: 0; right: 0; z-index: 9999;
    height: var(--nav-h);
    background: rgba(255,255,255,0.96);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border-bottom: 1px solid var(--border);
    display: flex; align-items: center; padding: 0 20px;
  }
  .dwj-nav-inner {
    width: 100%; max-width: 1160px; margin: 0 auto;
    display: flex; align-items: center; justify-content: space-between;
  }
  .dwj-logo {
    font-family: 'Fraunces', serif; font-weight: 900;
    font-size: 1.1rem; color: var(--ink);
    display: flex; align-items: center; gap: 8px;
    letter-spacing: -.02em; flex-shrink: 0;
  }
  .dwj-logo-dot {
    width: 8px; height: 8px; border-radius: 50%;
    background: var(--red); display: inline-block; flex-shrink: 0;
    animation: dotpulse 2s ease-in-out infinite;
  }
  @keyframes dotpulse { 0%,100%{opacity:1} 50%{opacity:.3} }

  .dwj-nav-links { display: flex; align-items: center; gap: 24px; list-style: none; }
  .dwj-nav-links a {
    font-size: .83rem; font-weight: 500; color: var(--mid);
    transition: color .2s; white-space: nowrap;
  }
  .dwj-nav-links a:hover { color: var(--ink); }
  .dwj-nav-cta {
    background: var(--ink) !important; color: #fff !important;
    padding: 7px 16px; border-radius: 99px;
    font-size: .8rem !important; font-weight: 600 !important;
    transition: background .2s !important;
  }
  .dwj-nav-cta:hover { background: var(--accent) !important; }

  .dwj-ham {
    display: none; flex-direction: column; gap: 5px;
    background: none; border: none; padding: 4px; flex-shrink: 0;
  }
  .dwj-ham span {
    display: block; width: 22px; height: 2px;
    background: var(--ink); border-radius: 2px;
    transition: transform .3s, opacity .3s;
  }
  .dwj-ham.open span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
  .dwj-ham.open span:nth-child(2) { opacity: 0; }
  .dwj-ham.open span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }

  .dwj-mob {
    display: none; position: fixed;
    top: var(--nav-h); left: 0; right: 0;
    background: var(--white); border-bottom: 1px solid var(--border);
    z-index: 9998; padding: 12px 20px 18px;
    flex-direction: column; gap: 2px;
    box-shadow: 0 8px 28px rgba(0,0,0,.08);
  }
  .dwj-mob.open { display: flex; }
  .dwj-mob a {
    display: block; padding: 11px 0;
    font-size: .9rem; font-weight: 500; color: var(--mid);
    border-bottom: 1px solid var(--border); transition: color .2s;
  }
  .dwj-mob a:last-child { border-bottom: none; color: var(--accent); font-weight: 600; }
  .dwj-mob a:hover { color: var(--ink); }

  /* HERO */
  .dwj-hero {
    min-height: 100vh;
    padding: calc(var(--nav-h) + 64px) 20px 64px;
    display: flex; align-items: center;
    background: var(--white);
    position: relative; overflow: hidden;
  }
  .dwj-hero::before {
    content: ''; position: absolute; inset: 0; pointer-events: none;
    background-image:
      linear-gradient(var(--border) 1px, transparent 1px),
      linear-gradient(90deg, var(--border) 1px, transparent 1px);
    background-size: 52px 52px; opacity: .28;
  }
  .dwj-hero::after {
    content: ''; position: absolute; inset: 0; pointer-events: none;
    background:
      radial-gradient(ellipse 55% 65% at 100% 30%, rgba(26,26,255,.05) 0%, transparent 60%),
      radial-gradient(ellipse 40% 50% at 0% 90%, rgba(255,58,45,.04) 0%, transparent 60%);
  }
  .dwj-hero-inner {
    width: 100%; max-width: 1160px; margin: 0 auto;
    display: grid; grid-template-columns: 1fr 400px; gap: 64px; align-items: center;
    position: relative; z-index: 1;
  }
  .dwj-hero-badge {
    display: inline-flex; align-items: center; gap: 7px;
    background: var(--off); border: 1px solid var(--border);
    padding: 5px 12px; border-radius: 99px;
    font-family: 'Space Mono', monospace; font-size: .67rem;
    color: var(--muted); letter-spacing: .07em; text-transform: uppercase;
    margin-bottom: 22px; animation: fadeUp .5s .1s both;
  }
  .gdot {
    width: 6px; height: 6px; border-radius: 50%;
    background: var(--green); flex-shrink: 0;
    animation: dotpulse 2s ease-in-out infinite;
  }
  .dwj-hero-title {
    font-family: 'Fraunces', serif; font-weight: 900;
    font-size: clamp(2.8rem, 5.5vw, 5rem);
    line-height: 1.02; letter-spacing: -.03em; color: var(--ink);
    animation: fadeUp .5s .2s both;
  }
  .dwj-hero-title em { font-style: italic; color: var(--accent); }
  .dwj-hero-title .t-red { color: var(--red); font-style: normal; }
  .dwj-hero-desc {
    margin-top: 18px; font-size: 1rem; color: var(--mid);
    max-width: 480px; line-height: 1.75;
    animation: fadeUp .5s .35s both;
  }
  .dwj-hero-chips {
    display: flex; flex-wrap: wrap; gap: 7px; margin-top: 24px;
    animation: fadeUp .5s .5s both;
  }
  .dwj-chip {
    font-family: 'Space Mono', monospace; font-size: .66rem;
    padding: 4px 11px; border-radius: 4px; border: 1px solid var(--border);
    color: var(--mid); letter-spacing: .03em;
    transition: border-color .2s, color .2s;
  }
  .dwj-chip:hover { border-color: var(--ink); color: var(--ink); }
  .dwj-hero-btns {
    display: flex; align-items: center; gap: 12px; margin-top: 32px; flex-wrap: wrap;
    animation: fadeUp .5s .65s both;
  }

  .dwj-btn {
    display: inline-block; padding: 12px 26px; border-radius: var(--radius);
    font-weight: 600; font-size: .88rem; transition: all .2s; text-align: center;
    border: none;
  }
  .dwj-btn-primary { background: var(--ink); color: #fff; }
  .dwj-btn-primary:hover { background: var(--accent); transform: translateY(-2px); }
  .dwj-btn-outline { border: 1.5px solid var(--border); color: var(--mid); background: transparent; }
  .dwj-btn-outline:hover { border-color: var(--ink); color: var(--ink); }

  /* Profile Card */
  .dwj-profile {
    background: var(--white); border: 1.5px solid var(--border);
    border-radius: 14px; padding: 28px; box-shadow: var(--shadow);
    animation: fadeUp .5s .3s both;
  }
  .dwj-profile-top { display: flex; align-items: center; gap: 14px; margin-bottom: 18px; }
  .dwj-avatar {
    width: 52px; height: 52px; border-radius: 50%; flex-shrink: 0;
    background: linear-gradient(135deg, var(--accent), var(--red));
    display: flex; align-items: center; justify-content: center;
    font-family: 'Fraunces', serif; font-weight: 900; font-size: 1.3rem; color: #fff;
  }
  .dwj-pname { font-family: 'Fraunces', serif; font-weight: 700; font-size: 1rem; }
  .dwj-prole { font-size: .78rem; color: var(--muted); margin-top: 2px; }
  .dwj-pbio {
    font-size: .86rem; color: var(--mid); line-height: 1.65;
    padding-bottom: 16px; border-bottom: 1px solid var(--border); margin-bottom: 16px;
  }
  .dwj-pstats {
    display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 16px;
  }
  .dwj-pstat { background: var(--off); border-radius: var(--radius); padding: 11px 13px; }
  .dwj-pstat-n { font-family: 'Fraunces', serif; font-weight: 700; font-size: 1.25rem; }
  .dwj-pstat-l { font-family: 'Space Mono', monospace; font-size: .65rem; color: var(--muted); margin-top: 1px; }
  .dwj-plinks { display: flex; flex-direction: column; gap: 7px; }
  .dwj-plink {
    display: flex; align-items: center; gap: 10px;
    padding: 9px 13px; border-radius: var(--radius); border: 1px solid var(--border);
    font-size: .82rem; font-weight: 500; color: var(--ink);
    transition: border-color .2s, background .2s;
  }
  .dwj-plink:hover { border-color: var(--ink); background: var(--off); }
  .dwj-plink-label { flex: 1; }
  .dwj-plink-arr { color: var(--muted); font-size: .72rem; }

  /* STATS BAR */
  .dwj-statsbar {
    background: var(--ink); color: #fff;
    padding: 16px 20px;
    display: flex; justify-content: center; align-items: center; flex-wrap: wrap;
  }
  .dwj-statsbar-item {
    text-align: center; padding: 8px 36px;
    border-right: 1px solid rgba(255,255,255,.1);
  }
  .dwj-statsbar-item:last-child { border-right: none; }
  .dwj-sn {
    font-family: 'Fraunces', serif; font-weight: 900; font-size: 1.5rem; line-height: 1;
  }
  .dwj-sl {
    font-family: 'Space Mono', monospace; font-size: .63rem;
    color: rgba(255,255,255,.45); margin-top: 4px;
    letter-spacing: .07em; text-transform: uppercase;
  }

  /* ADSENSE BANNER */
  .dwj-ad-banner {
    background: var(--off); border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
    padding: 10px 20px; text-align: center; overflow: hidden;
    min-height: 90px; display: flex; align-items: center; justify-content: center;
  }

  /* SECTIONS */
  .dwj-section { padding: 72px 0; }
  .dwj-section-off {
    background: var(--off);
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
  }
  .dwj-kicker {
    font-family: 'Space Mono', monospace; font-size: .68rem;
    text-transform: uppercase; letter-spacing: .12em;
    color: var(--muted); margin-bottom: 8px;
  }
  .dwj-title {
    font-family: 'Fraunces', serif; font-weight: 900;
    font-size: clamp(1.7rem, 3vw, 2.5rem);
    letter-spacing: -.02em; color: var(--ink); line-height: 1.1;
  }
  .dwj-desc { margin-top: 10px; color: var(--mid); font-size: .94rem; }
  .dwj-section-hrow {
    display: flex; align-items: flex-end; justify-content: space-between;
    gap: 16px; flex-wrap: wrap; margin-bottom: 36px;
  }
  .dwj-viewall {
    font-family: 'Space Mono', monospace; font-size: .72rem;
    color: var(--mid); border-bottom: 1px solid var(--border);
    padding-bottom: 2px; white-space: nowrap;
    transition: color .2s, border-color .2s;
  }
  .dwj-viewall:hover { color: var(--ink); border-color: var(--ink); }

  /* TOPICS GRID */
  .dwj-topics-grid { display: grid; grid-template-columns: repeat(6, 1fr); gap: 12px; }
  .dwj-topic {
    background: var(--white); border: 1px solid var(--border);
    border-radius: var(--radius); padding: 18px 12px;
    text-align: center; display: block;
    transition: transform .2s, box-shadow .2s;
  }
  .dwj-topic:hover { transform: translateY(-3px); box-shadow: var(--shadow); }
  .dwj-topic-icon { font-size: 1.4rem; margin-bottom: 7px; }
  .dwj-topic-name { font-family: 'Fraunces', serif; font-weight: 700; font-size: .84rem; color: var(--ink); }

  /* BLOG CARDS */
  .dwj-posts-grid, .dwj-allposts-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 24px;
  }
  .dwj-card {
    background: var(--white); border: 1px solid var(--border);
    border-radius: var(--radius); overflow: hidden;
    display: flex; flex-direction: column;
    transition: transform .25s, box-shadow .25s;
    color: var(--ink);
  }
  .dwj-card:hover { transform: translateY(-4px); box-shadow: var(--shadow-h); }
  .dwj-card-thumb {
    width: 100%; aspect-ratio: 16/9; overflow: hidden;
    background: var(--off); flex-shrink: 0;
  }
  .dwj-card-thumb img {
    width: 100%; height: 100%; object-fit: cover;
    transition: transform .4s ease; display: block;
  }
  .dwj-card:hover .dwj-card-thumb img { transform: scale(1.04); }
  .dwj-card-ph {
    width: 100%; height: 100%;
    background: linear-gradient(135deg, #f0efed, #e4e3e0);
    display: flex; align-items: center; justify-content: center;
    font-size: 2rem;
  }
  .dwj-card-body { padding: 18px; display: flex; flex-direction: column; flex-grow: 1; }
  .dwj-card-cat {
    font-family: 'Space Mono', monospace; font-size: .64rem;
    text-transform: uppercase; letter-spacing: .08em;
    color: var(--accent); margin-bottom: 8px;
  }
  .dwj-card-title {
    font-family: 'Fraunces', serif; font-weight: 700;
    font-size: 1.05rem; line-height: 1.35; color: var(--ink); margin-bottom: 9px;
  }
  .dwj-card-snip {
    font-size: .84rem; color: var(--mid); line-height: 1.6;
    display: -webkit-box; -webkit-line-clamp: 3;
    -webkit-box-orient: vertical; overflow: hidden;
    margin-bottom: 14px; flex-grow: 1;
  }
  .dwj-card-foot {
    display: flex; align-items: center; justify-content: space-between;
    padding-top: 12px; border-top: 1px solid var(--border); margin-top: auto;
  }
  .dwj-card-date { font-family: 'Space Mono', monospace; font-size: .64rem; color: var(--muted); }
  .dwj-card-read {
    font-family: 'Space Mono', monospace; font-size: .67rem; font-weight: 700;
    color: var(--accent); letter-spacing: .04em; transition: letter-spacing .2s;
  }
  .dwj-card:hover .dwj-card-read { letter-spacing: .1em; }

  /* ABOUT + SOCIAL */
  .dwj-about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 64px; align-items: start; }
  .dwj-about-desc { margin-top: 14px; color: var(--mid); font-size: .96rem; line-height: 1.78; }
  .dwj-about-tags { display: flex; flex-wrap: wrap; gap: 7px; margin-top: 20px; }
  .dwj-atag {
    font-family: 'Space Mono', monospace; font-size: .66rem;
    padding: 4px 11px; border-radius: 4px; border: 1px solid var(--border);
    color: var(--mid); background: var(--white);
  }
  .dwj-about-btns { display: flex; gap: 10px; flex-wrap: wrap; margin-top: 24px; }
  .dwj-info-list { display: flex; flex-direction: column; gap: 10px; }
  .dwj-info-row {
    display: flex; align-items: flex-start; gap: 12px;
    background: var(--white); border: 1px solid var(--border);
    border-radius: var(--radius); padding: 13px 16px;
  }
  .dwj-info-icon { font-size: 1.1rem; flex-shrink: 0; margin-top: 2px; }
  .dwj-info-lbl { font-family: 'Space Mono', monospace; font-size: .65rem; color: var(--muted); margin-bottom: 2px; }
  .dwj-info-val { font-size: .88rem; font-weight: 600; color: var(--ink); }

  .dwj-social-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 14px; }
  .dwj-social {
    border: 1.5px solid var(--border); border-radius: 12px;
    padding: 22px 18px; display: flex; flex-direction: column; gap: 10px;
    transition: transform .25s, box-shadow .25s, border-color .25s;
    position: relative; overflow: hidden;
  }
  .dwj-social:hover { transform: translateY(-4px); box-shadow: var(--shadow-h); border-color: transparent; }
  .dwj-social::after {
    content: ''; position: absolute; bottom: 0; left: 0; right: 0; height: 3px;
    background: var(--sc, var(--ink));
    transform: scaleX(0); transform-origin: left; transition: transform .3s;
  }
  .dwj-social:hover::after { transform: scaleX(1); }
  .dwj-social-icon { font-size: 1.5rem; }
  .dwj-social-name { font-family: 'Fraunces', serif; font-weight: 700; font-size: .96rem; }
  .dwj-social-handle { font-family: 'Space Mono', monospace; font-size: .67rem; color: var(--muted); }
  .dwj-social-act { font-family: 'Space Mono', monospace; font-size: .67rem; color: var(--mid); margin-top: auto; transition: color .2s; }
  .dwj-social:hover .dwj-social-act { color: var(--ink); }

  /* NEWSLETTER */
  .dwj-nl {
    background: var(--ink); color: #fff;
    padding: 72px 20px; text-align: center; position: relative; overflow: hidden;
  }
  .dwj-nl::before {
    content: ''; position: absolute; inset: 0; pointer-events: none;
    background:
      radial-gradient(ellipse 50% 80% at 20% 50%, rgba(26,26,255,.22) 0%, transparent 60%),
      radial-gradient(ellipse 40% 60% at 80% 50%, rgba(255,58,45,.15) 0%, transparent 60%);
  }
  .dwj-nl-inner { position: relative; z-index: 1; max-width: 500px; margin: 0 auto; }
  .dwj-nl .dwj-kicker { color: rgba(255,255,255,.3); }
  .dwj-nl .dwj-title { color: #fff; }
  .dwj-nl .dwj-desc { color: rgba(255,255,255,.5); margin: 10px auto 28px; max-width: 380px; }
  .dwj-nl-form { display: flex; gap: 8px; flex-wrap: wrap; justify-content: center; }
  .dwj-nl-input {
    flex: 1; min-width: 200px; padding: 12px 18px; border-radius: var(--radius);
    background: rgba(255,255,255,.08); border: 1.5px solid rgba(255,255,255,.12);
    color: #fff; font-size: .9rem; font-family: 'DM Sans', sans-serif; outline: none;
    transition: border-color .2s;
  }
  .dwj-nl-input::placeholder { color: rgba(255,255,255,.3); }
  .dwj-nl-input:focus { border-color: var(--accent); }
  .dwj-nl-btn {
    background: #fff; color: var(--ink);
    padding: 12px 22px; border-radius: var(--radius);
    font-weight: 700; font-size: .86rem; border: none;
    transition: background .2s, transform .2s; white-space: nowrap;
  }
  .dwj-nl-btn:hover { background: var(--accent); color: #fff; transform: translateY(-2px); }
  .dwj-nl-btn:disabled { opacity: .6; cursor: not-allowed; transform: none; }
  .dwj-nl-note { margin-top: 12px; font-size: .73rem; color: rgba(255,255,255,.28); }

  /* ALL POSTS PAGE */
  .dwj-ap-header { text-align: center; padding: calc(var(--nav-h) + 56px) 20px 48px; }
  .dwj-search-wrap { position: relative; max-width: 400px; margin: 24px auto 0; }
  .dwj-search-ico {
    position: absolute; left: 13px; top: 50%; transform: translateY(-50%);
    color: var(--muted); font-size: .85rem; pointer-events: none;
  }
  .dwj-search {
    width: 100%; padding: 11px 14px 11px 38px;
    border: 1.5px solid var(--border); border-radius: var(--radius);
    font-size: .88rem; font-family: 'DM Sans', sans-serif;
    background: var(--white); color: var(--ink); outline: none; transition: border-color .2s;
  }
  .dwj-search:focus { border-color: var(--accent); }
  .dwj-search::placeholder { color: var(--muted); }

  .dwj-spinner {
    width: 28px; height: 28px; border: 3px solid var(--border);
    border-top-color: var(--accent); border-radius: 50%;
    animation: spin .8s linear infinite; margin: 0 auto 14px;
  }
  @keyframes spin { to { transform: rotate(360deg); } }

  /* SINGLE POST */
  .dwj-post-wrap { max-width: 720px; margin: calc(var(--nav-h) + 48px) auto 80px; padding: 0 20px; }
  .dwj-post-back {
    display: inline-flex; align-items: center; gap: 6px;
    font-family: 'Space Mono', monospace; font-size: .72rem;
    color: var(--mid); margin-bottom: 28px;
    border-bottom: 1px solid transparent; transition: color .2s, border-color .2s;
  }
  .dwj-post-back:hover { color: var(--ink); border-color: var(--ink); }
  .dwj-post-cat {
    font-family: 'Space Mono', monospace; font-size: .7rem;
    text-transform: uppercase; letter-spacing: .1em; color: var(--accent);
    display: block; margin-bottom: 14px;
  }
  .dwj-post-title {
    font-family: 'Fraunces', serif; font-weight: 900;
    font-size: clamp(1.9rem, 4.5vw, 3rem); line-height: 1.12;
    letter-spacing: -.025em; color: var(--ink); margin-bottom: 16px;
  }
  .dwj-post-meta {
    font-family: 'Space Mono', monospace; font-size: .76rem; color: var(--muted);
    padding-bottom: 22px; border-bottom: 1px solid var(--border); margin-bottom: 32px;
    display: flex; flex-wrap: wrap; gap: 10px; align-items: center;
  }
  .dwj-ad-inarticle {
    background: var(--off); border: 1px solid var(--border);
    border-radius: var(--radius); padding: 16px; margin: 36px 0;
    text-align: center; min-height: 280px;
    display: flex; align-items: center; justify-content: center; overflow: hidden;
  }
  .dwj-post-body { font-size: 1.08rem; line-height: 1.85; color: #1a1a18; }
  .dwj-post-body p { margin-bottom: 24px; }
  .dwj-post-body h2 { font-family: 'Fraunces', serif; font-weight: 700; font-size: 1.55rem; margin: 38px 0 14px; letter-spacing: -.01em; }
  .dwj-post-body h3 { font-family: 'Fraunces', serif; font-weight: 700; font-size: 1.2rem; margin: 30px 0 12px; }
  .dwj-post-body img { border-radius: var(--radius); margin: 28px 0; width: 100%; }
  .dwj-post-body a { color: var(--accent); text-decoration: underline; text-underline-offset: 3px; }
  .dwj-post-body ul, .dwj-post-body ol { padding-left: 22px; margin-bottom: 24px; }
  .dwj-post-body li { margin-bottom: 7px; }
  .dwj-post-body blockquote {
    border-left: 3px solid var(--accent); padding: 14px 18px;
    background: var(--off); margin: 28px 0; border-radius: 0 4px 4px 0;
    font-style: italic; color: var(--mid);
  }
  .dwj-post-body pre {
    background: var(--ink); color: #fff; padding: 22px;
    border-radius: var(--radius); overflow-x: auto;
    font-family: 'Space Mono', monospace; font-size: .82rem; margin: 28px 0;
  }
  .dwj-post-body code {
    background: var(--off); color: var(--red); padding: 2px 6px;
    border-radius: 3px; font-family: 'Space Mono', monospace; font-size: .82em;
  }
  .dwj-post-body pre code { background: none; color: inherit; padding: 0; }
  .dwj-post-body table { width: 100%; border-collapse: collapse; margin: 24px 0; font-size: .92rem; }
  .dwj-post-body th, .dwj-post-body td { border: 1px solid var(--border); padding: 10px 14px; text-align: left; }
  .dwj-post-body th { background: var(--off); font-weight: 600; }

  .dwj-post-share {
    display: flex; align-items: center; gap: 10px; flex-wrap: wrap;
    margin-top: 48px; padding-top: 28px; border-top: 1px solid var(--border);
  }
  .dwj-share-lbl { font-family: 'Space Mono', monospace; font-size: .7rem; color: var(--muted); margin-right: 4px; }
  .dwj-share-btn {
    display: inline-flex; align-items: center; gap: 6px;
    padding: 8px 14px; border-radius: 99px; border: 1px solid var(--border);
    font-family: 'Space Mono', monospace; font-size: .68rem; font-weight: 700;
    color: var(--mid); transition: border-color .2s, color .2s, background .2s;
  }
  .dwj-share-btn:hover { border-color: var(--ink); color: var(--ink); background: var(--off); }

  /* PAGINATION */
  .dwj-pagination {
    display: flex; justify-content: center; align-items: center;
    gap: 10px; padding: 40px 0; flex-wrap: wrap;
  }
  .dwj-pagination a {
    display: inline-flex; align-items: center; gap: 6px;
    padding: 9px 18px; border-radius: var(--radius);
    border: 1.5px solid var(--border); font-family: 'Space Mono', monospace;
    font-size: .72rem; font-weight: 700; color: var(--mid);
    transition: border-color .2s, color .2s, background .2s;
  }
  .dwj-pagination a:hover { border-color: var(--ink); color: var(--ink); background: var(--off); }

  /* FOOTER */
  .dwj-footer { background: var(--ink); color: rgba(255,255,255,.5); padding: 52px 20px 28px; }
  .dwj-footer-grid {
    width: 100%; max-width: 1160px; margin: 0 auto;
    display: grid; grid-template-columns: 1.3fr 1fr 1fr 1fr; gap: 40px;
    padding-bottom: 36px; border-bottom: 1px solid rgba(255,255,255,.08); margin-bottom: 24px;
  }
  .dwj-footer-brand {
    font-family: 'Fraunces', serif; font-weight: 900;
    font-size: 1.15rem; color: #fff; display: block; margin-bottom: 10px;
  }
  .dwj-footer-desc { font-size: .83rem; line-height: 1.7; max-width: 230px; }
  .dwj-footer-head { font-family: 'Fraunces', serif; font-weight: 700; color: #fff; font-size: .88rem; margin-bottom: 12px; }
  .dwj-footer-ul { list-style: none; display: flex; flex-direction: column; gap: 8px; }
  .dwj-footer-ul a { font-size: .82rem; color: rgba(255,255,255,.4); transition: color .2s; }
  .dwj-footer-ul a:hover { color: #fff; }
  .dwj-footer-bottom {
    width: 100%; max-width: 1160px; margin: 0 auto;
    display: flex; justify-content: space-between; align-items: center;
    font-size: .76rem; flex-wrap: wrap; gap: 10px;
  }

  #dwj-btt {
    position: fixed; bottom: 24px; right: 24px; z-index: 900;
    width: 40px; height: 40px; border-radius: 50%;
    background: var(--ink); color: #fff; border: none;
    font-size: .9rem; box-shadow: 0 4px 16px rgba(0,0,0,.18);
    display: flex; align-items: center; justify-content: center;
    opacity: 0; pointer-events: none; transition: opacity .3s, transform .2s;
  }
  #dwj-btt.show { opacity: 1; pointer-events: all; }
  #dwj-btt:hover { transform: translateY(-3px); }

  @keyframes fadeUp { from{opacity:0;transform:translateY(18px);} to{opacity:1;transform:none;} }

  @media (max-width:1024px) {
    .dwj-hero-inner    { grid-template-columns: 1fr; gap: 40px; }
    .dwj-hero          { min-height: auto; padding-bottom: 52px; }
    .dwj-profile       { max-width: 520px; }
    .dwj-posts-grid    { grid-template-columns: repeat(2,1fr); gap: 20px; }
    .dwj-allposts-grid { grid-template-columns: repeat(2,1fr); gap: 20px; }
    .dwj-social-grid   { grid-template-columns: repeat(2,1fr); }
    .dwj-topics-grid   { grid-template-columns: repeat(3,1fr); }
    .dwj-about-grid    { grid-template-columns: 1fr; gap: 36px; }
    .dwj-footer-grid   { grid-template-columns: 1fr 1fr; gap: 28px; }
    .dwj-statsbar-item { padding: 8px 24px; }
  }

  @media (max-width:768px) {
    .dwj-nav-links     { display: none; }
    .dwj-ham           { display: flex; }
    .dwj-hero          { padding-top: calc(var(--nav-h) + 36px); padding-bottom: 40px; }
    .dwj-hero-title    { font-size: clamp(2.2rem,8vw,3.2rem); }
    .dwj-posts-grid    { grid-template-columns: 1fr; gap: 16px; }
    .dwj-allposts-grid { grid-template-columns: 1fr; gap: 16px; }
    .dwj-social-grid   { grid-template-columns: 1fr 1fr; }
    .dwj-topics-grid   { grid-template-columns: repeat(3,1fr); gap: 8px; }
    .dwj-section       { padding: 52px 0; }
    .dwj-section-hrow  { flex-direction: column; align-items: flex-start; }
    .dwj-statsbar-item { padding: 10px 16px; flex: 1 0 50%; }
    .dwj-statsbar-item:nth-child(2) { border-right: none; }
    .dwj-footer-grid   { grid-template-columns: 1fr; gap: 24px; }
    .dwj-footer-desc   { max-width: 100%; }
    .dwj-footer-bottom { flex-direction: column; text-align: center; }
  }

  @media (max-width:480px) {
    .dwj-hero-title    { font-size: 2.1rem; }
    .dwj-social-grid   { grid-template-columns: 1fr; }
    .dwj-topics-grid   { grid-template-columns: repeat(2,1fr); }
    .dwj-hero-btns     { flex-direction: column; align-items: stretch; }
    .dwj-btn           { width: 100%; }
    .dwj-nl-form       { flex-direction: column; }
    .dwj-nl-input, .dwj-nl-btn { width: 100%; }
    .dwj-about-btns    { flex-direction: column; }
    .dwj-about-btns .dwj-btn { width: 100%; }
    .dwj-profile       { padding: 20px; }
    .dwj-post-title    { font-size: 1.7rem; }
    .dwj-posts-grid    { grid-template-columns: 1fr; }
  }

  body#layout .dwj-nav, body#layout .dwj-mob, body#layout .dwj-hero,
  body#layout .dwj-statsbar, body#layout .dwj-ad-banner, body#layout #dwj-topics,
  body#layout #dwj-about, body#layout #dwj-connect, body#layout .dwj-nl,
  body#layout .dwj-footer, body#layout #dwj-btt { display: none !important; }
  body#layout .dwj-posts-grid, body#layout .dwj-allposts-grid { grid-template-columns: 1fr !important; gap: 10px !important; }
  body#layout .dwj-section { padding: 12px 0 !important; }
  body#layout .dwj-wrap { padding: 0 !important; max-width: 100% !important; }

  .sr-only {
    position: absolute; width: 1px; height: 1px;
    padding: 0; margin: -1px; overflow: hidden;
    clip: rect(0,0,0,0); white-space: nowrap; border: 0;
  }


  /* TECH BLOG REFRESH + DARK MODE */
  :root {
    --white:#ffffff;
    --off:#f3f6fb;
    --ink:#0f172a;
    --mid:#475569;
    --muted:#64748b;
    --border:#e2e8f0;
    --accent:#2563eb;
    --red:#7c3aed;
    --green:#10b981;
    --radius:12px;
    --shadow:0 8px 28px rgba(15,23,42,.07);
    --shadow-h:0 18px 50px rgba(15,23,42,.12);
  }
  body.dwj-dark {
    --white:#07111f;
    --off:#0f172a;
    --ink:#f8fafc;
    --mid:#cbd5e1;
    --muted:#94a3b8;
    --border:#1e293b;
    --accent:#38bdf8;
    --red:#a78bfa;
    --green:#34d399;
    background:#07111f;
    color:#f8fafc;
  }
  body.dwj-dark .dwj-nav,
  body.dwj-dark .dwj-mob,
  body.dwj-dark .dwj-profile,
  body.dwj-dark .dwj-card,
  body.dwj-dark .dwj-topic,
  body.dwj-dark .dwj-info-row,
  body.dwj-dark .dwj-social,
  body.dwj-dark .dwj-post-body,
  body.dwj-dark .dwj-search { background:#0f172a; }
  body.dwj-dark .dwj-card-ph { background:linear-gradient(135deg,#0f172a,#1e293b); }
  body.dwj-dark .dwj-hero { background:#07111f; }
  body.dwj-dark .dwj-section-off { background:#0b1220; }
  body.dwj-dark .dwj-pstat { background:#111c33; }
  body.dwj-dark .dwj-footer { background:#020617; }
  .dwj-theme-toggle {
    width:38px;height:38px;border-radius:999px;border:1px solid var(--border);
    background:var(--white);color:var(--ink);font-weight:800;font-size:.9rem;
    display:flex;align-items:center;justify-content:center;margin-left:4px;
    transition:transform .2s, box-shadow .2s, border-color .2s;
  }
  .dwj-theme-toggle:hover { transform:translateY(-2px); box-shadow:var(--shadow); border-color:var(--accent); }
  .dwj-hero-title em { color:var(--accent); }
  .dwj-hero-title .t-red { color:var(--red); }
  .dwj-card-cat, .dwj-card-read, .dwj-post-cat, .dwj-post-body a { color:var(--accent); }


/* ==========================
   DARK MODE TEXT FIX
   Light mode stays default.
   Dark mode text/background fixed.
========================== */

body.dark-mode{
  --white:#0f172a;
  --off:#111827;
  --ink:#f8fafc;
  --mid:#cbd5e1;
  --muted:#94a3b8;
  --border:#334155;
  --card:#111827;
  --soft:#0f172a;
  background:#0f172a !important;
  color:#f8fafc !important;
}

body.dark-mode,
body.dark-mode *{
  color:var(--ink) !important;
}

body.dark-mode p,
body.dark-mode span,
body.dark-mode small,
body.dark-mode li,
body.dark-mode .dwj-desc,
body.dark-mode .dwj-hero-desc,
body.dark-mode .dwj-card-snip,
body.dark-mode .dwj-card-date,
body.dark-mode .dwj-post-meta,
body.dark-mode .dwj-pbio,
body.dark-mode .dwj-prole,
body.dark-mode .dwj-pstat-l,
body.dark-mode .dwj-info-lbl,
body.dark-mode .dwj-social-handle,
body.dark-mode .dwj-social-act,
body.dark-mode .dwj-footer-desc,
body.dark-mode .dwj-footer-bottom{
  color:var(--muted) !important;
}

body.dark-mode a,
body.dark-mode h1,
body.dark-mode h2,
body.dark-mode h3,
body.dark-mode h4,
body.dark-mode h5,
body.dark-mode h6,
body.dark-mode .dwj-logo,
body.dark-mode .dwj-title,
body.dark-mode .dwj-hero-title,
body.dark-mode .dwj-card-title,
body.dark-mode .dwj-post-title,
body.dark-mode .dwj-pname,
body.dark-mode .dwj-pstat-n,
body.dark-mode .dwj-info-val,
body.dark-mode .dwj-topic-name,
body.dark-mode .dwj-social-name{
  color:var(--ink) !important;
}

body.dark-mode .dwj-nav,
body.dark-mode .dwj-mob,
body.dark-mode .dwj-profile,
body.dark-mode .dwj-card,
body.dark-mode .dwj-topic,
body.dark-mode .dwj-info-row,
body.dark-mode .dwj-social,
body.dark-mode .dwj-post-body,
body.dark-mode .dwj-search,
body.dark-mode .dwj-pstat{
  background:#111827 !important;
  border-color:#334155 !important;
}

body.dark-mode .dwj-hero,
body.dark-mode .dwj-section-off,
body.dark-mode .dwj-ad-banner,
body.dark-mode .dwj-card-ph,
body.dark-mode .dwj-search{
  background:#0f172a !important;
}

body.dark-mode .dwj-btn-outline,
body.dark-mode .dwj-chip,
body.dark-mode .dwj-atag,
body.dark-mode .dwj-share-btn,
body.dark-mode .dwj-viewall{
  color:#f8fafc !important;
  border-color:#334155 !important;
}

body.dark-mode .dwj-btn-primary,
body.dark-mode .dwj-nav-cta{
  background:#3157ff !important;
  color:#ffffff !important;
}

body.dark-mode .dwj-footer,
body.dark-mode .dwj-nl{
  background:#050816 !important;
}

body.dark-mode .dwj-footer *,
body.dark-mode .dwj-nl *{
  color:rgba(255,255,255,.78) !important;
}

body.dark-mode .dwj-footer h3,
body.dark-mode .dwj-footer h4,
body.dark-mode .dwj-footer-brand,
body.dark-mode .dwj-nl .dwj-title{
  color:#ffffff !important;
}


/* ==========================
   DARK MODE PATCH V2
   Fixes:
   - White newsletter/open section
   - Blog post body dark text
   - Buttons becoming white/invisible
   - Post content container colors
========================== */

body.dark-mode .dwj-nl,
body.dark-mode .dwj-newsletter,
body.dark-mode .newsletter,
body.dark-mode section.dwj-nl,
body.dark-mode .dwj-section.dwj-nl,
body.dark-mode .dwj-section-off,
body.dark-mode .dwj-hero,
body.dark-mode .dwj-ap-header{
  background:#050b18 !important;
  color:#f8fafc !important;
}

body.dark-mode .dwj-nl::before,
body.dark-mode .dwj-hero::before,
body.dark-mode .dwj-hero::after{
  opacity:.35 !important;
}

body.dark-mode .dwj-nl *,
body.dark-mode .dwj-newsletter *,
body.dark-mode .newsletter *{
  color:#f8fafc !important;
}

body.dark-mode .dwj-nl p,
body.dark-mode .dwj-newsletter p,
body.dark-mode .newsletter p,
body.dark-mode .dwj-nl-note{
  color:#cbd5e1 !important;
}

body.dark-mode .dwj-nl-input,
body.dark-mode .newsletter input,
body.dark-mode input[type="email"]{
  background:#111827 !important;
  border-color:#334155 !important;
  color:#f8fafc !important;
}

body.dark-mode .dwj-nl-input::placeholder,
body.dark-mode .newsletter input::placeholder{
  color:#94a3b8 !important;
}

body.dark-mode .dwj-btn-primary,
body.dark-mode .dwj-nl-btn,
body.dark-mode button.dwj-nl-btn,
body.dark-mode .dwj-hero-btns .dwj-btn-primary{
  background:#3157ff !important;
  color:#ffffff !important;
  border-color:#3157ff !important;
}

body.dark-mode .dwj-btn-outline,
body.dark-mode .dwj-hero-btns .dwj-btn-outline{
  background:#111827 !important;
  color:#f8fafc !important;
  border-color:#334155 !important;
}

body.dark-mode .dwj-btn-outline:hover,
body.dark-mode .dwj-hero-btns .dwj-btn-outline:hover{
  background:#1e293b !important;
  color:#ffffff !important;
}

/* Single post page exact fixes */
body.dark-mode .dwj-post-wrap,
body.dark-mode article.dwj-post-wrap{
  background:#111827 !important;
  color:#f8fafc !important;
}

body.dark-mode .dwj-post-body,
body.dark-mode .post-body,
body.dark-mode .entry-content,
body.dark-mode .post {
  background:#111827 !important;
  color:#e5e7eb !important;
}

body.dark-mode .dwj-post-body *,
body.dark-mode .post-body *,
body.dark-mode .entry-content *,
body.dark-mode .post *{
  color:#e5e7eb !important;
}

body.dark-mode .dwj-post-body p,
body.dark-mode .post-body p,
body.dark-mode .entry-content p,
body.dark-mode .post p,
body.dark-mode .dwj-post-body li,
body.dark-mode .post-body li{
  color:#d1d5db !important;
}

body.dark-mode .dwj-post-body h1,
body.dark-mode .dwj-post-body h2,
body.dark-mode .dwj-post-body h3,
body.dark-mode .dwj-post-body h4,
body.dark-mode .post-body h1,
body.dark-mode .post-body h2,
body.dark-mode .post-body h3,
body.dark-mode .post-body h4,
body.dark-mode .entry-content h1,
body.dark-mode .entry-content h2,
body.dark-mode .entry-content h3,
body.dark-mode .entry-content h4{
  color:#ffffff !important;
}

body.dark-mode .dwj-post-body a,
body.dark-mode .post-body a,
body.dark-mode .entry-content a{
  color:#7dd3fc !important;
}

body.dark-mode .dwj-post-body blockquote,
body.dark-mode .post-body blockquote{
  background:#0f172a !important;
  border-left-color:#38bdf8 !important;
  color:#cbd5e1 !important;
}

body.dark-mode .dwj-post-body code,
body.dark-mode .post-body code{
  background:#0f172a !important;
  color:#fca5a5 !important;
}

body.dark-mode .dwj-post-body pre,
body.dark-mode .post-body pre{
  background:#020617 !important;
  color:#f8fafc !important;
}

body.dark-mode .dwj-post-meta,
body.dark-mode .dwj-post-meta *,
body.dark-mode .dwj-post-cat{
  color:#94a3b8 !important;
}

body.dark-mode .dwj-post-title{
  color:#ffffff !important;
}

/* Fix accidental white panels in dark mode */
body.dark-mode [style*="background:#fff"],
body.dark-mode [style*="background: #fff"],
body.dark-mode [style*="background:white"],
body.dark-mode [style*="background: white"],
body.dark-mode [style*="background-color:#fff"],
body.dark-mode [style*="background-color: #fff"],
body.dark-mode [style*="background-color:white"],
body.dark-mode [style*="background-color: white"]{
  background:#111827 !important;
}

/* Back to top button visible */
body.dark-mode #dwj-btt{
  background:#3157ff !important;
  color:#ffffff !important;
}


/* ==========================
   PHASE 2 HOMEPAGE SECTIONS
   Featured Article + Topic Hubs + Newsletter
========================== */

.dwj-phase2-section{
  padding:72px 20px;
  background:#fff;
}
.dwj-phase2-section.off{
  background:#f8f8f6;
  border-top:1px solid var(--border);
  border-bottom:1px solid var(--border);
}
.dwj-phase2-wrap{
  width:100%;
  max-width:1160px;
  margin:0 auto;
}
.dwj-phase2-head{
  display:flex;
  align-items:flex-end;
  justify-content:space-between;
  gap:20px;
  margin-bottom:32px;
  flex-wrap:wrap;
}
.dwj-phase2-kicker{
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  text-transform:uppercase;
  letter-spacing:.12em;
  color:var(--muted);
  margin-bottom:8px;
}
.dwj-phase2-title{
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:clamp(1.8rem,3.4vw,2.8rem);
  line-height:1.05;
  letter-spacing:-.03em;
  color:var(--ink);
}
.dwj-phase2-desc{
  color:var(--mid);
  font-size:.95rem;
  margin-top:10px;
  max-width:520px;
}
.dwj-phase2-link{
  font-family:'Space Mono',monospace;
  font-size:.75rem;
  font-weight:700;
  color:var(--accent);
  border-bottom:1px solid var(--accent);
}

/* Featured */
.dwj-featured-box{
  display:grid;
  grid-template-columns:1.15fr .85fr;
  gap:28px;
  align-items:stretch;
  background:#fff;
  border:1px solid var(--border);
  border-radius:20px;
  overflow:hidden;
  box-shadow:0 16px 50px rgba(0,0,0,.08);
}
.dwj-featured-media{
  min-height:360px;
  background:linear-gradient(135deg,#eef2ff,#f8f8f6);
  overflow:hidden;
}
.dwj-featured-media img{
  width:100%;
  height:100%;
  object-fit:cover;
}
.dwj-featured-placeholder{
  width:100%;
  height:100%;
  min-height:360px;
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:4rem;
  background:
    radial-gradient(circle at 20% 20%,rgba(26,26,255,.15),transparent 35%),
    radial-gradient(circle at 80% 60%,rgba(255,58,45,.10),transparent 35%),
    #f8f8f6;
}
.dwj-featured-content{
  padding:38px;
  display:flex;
  flex-direction:column;
  justify-content:center;
}
.dwj-featured-badge{
  display:inline-flex;
  align-items:center;
  width:max-content;
  gap:7px;
  font-family:'Space Mono',monospace;
  font-size:.66rem;
  text-transform:uppercase;
  letter-spacing:.08em;
  background:#0a0a0a;
  color:#fff;
  padding:6px 12px;
  border-radius:999px;
  margin-bottom:16px;
}
.dwj-featured-cat{
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  color:var(--accent);
  text-transform:uppercase;
  letter-spacing:.08em;
  margin-bottom:10px;
}
.dwj-featured-title{
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:clamp(1.9rem,3.5vw,3rem);
  line-height:1.08;
  letter-spacing:-.03em;
  margin-bottom:16px;
}
.dwj-featured-title a{color:var(--ink);}
.dwj-featured-snip{
  color:var(--mid);
  font-size:1rem;
  line-height:1.75;
  margin-bottom:24px;
}
.dwj-featured-btn{
  display:inline-flex;
  width:max-content;
  padding:12px 22px;
  border-radius:8px;
  background:var(--ink);
  color:#fff!important;
  font-size:.88rem;
  font-weight:700;
  transition:.2s;
}
.dwj-featured-btn:hover{
  background:var(--accent);
  transform:translateY(-2px);
}
.dwj-featured-loading,
.dwj-featured-empty{
  padding:48px 24px;
  text-align:center;
  color:var(--muted);
  border:1px dashed var(--border);
  border-radius:18px;
  background:#fff;
  font-family:'Space Mono',monospace;
  font-size:.78rem;
}

/* Topic hubs */
.dwj-topic-hubs-grid{
  display:grid;
  grid-template-columns:repeat(6,1fr);
  gap:14px;
}
.dwj-hub-card{
  background:#fff;
  border:1px solid var(--border);
  border-radius:16px;
  padding:22px 16px;
  min-height:170px;
  transition:.22s;
  display:flex;
  flex-direction:column;
}
.dwj-hub-card:hover{
  transform:translateY(-4px);
  box-shadow:var(--shadow-h);
  border-color:#d7d7d3;
}
.dwj-hub-icon{
  font-size:1.75rem;
  margin-bottom:12px;
}
.dwj-hub-name{
  font-family:'Fraunces',serif;
  font-weight:800;
  font-size:1rem;
  color:var(--ink);
  margin-bottom:8px;
}
.dwj-hub-desc{
  color:var(--mid);
  font-size:.82rem;
  line-height:1.5;
  margin-bottom:14px;
}
.dwj-hub-link{
  margin-top:auto;
  font-family:'Space Mono',monospace;
  font-size:.66rem;
  color:var(--accent);
  font-weight:700;
}

/* Newsletter */
.dwj-phase2-newsletter{
  background:var(--ink);
  color:#fff;
  border-radius:24px;
  padding:56px 32px;
  text-align:center;
  position:relative;
  overflow:hidden;
}
.dwj-phase2-newsletter::before{
  content:'';
  position:absolute;
  inset:0;
  background:
    radial-gradient(circle at 20% 20%,rgba(26,26,255,.25),transparent 35%),
    radial-gradient(circle at 80% 70%,rgba(255,58,45,.16),transparent 35%);
  pointer-events:none;
}
.dwj-phase2-newsletter > *{
  position:relative;
  z-index:1;
}
.dwj-phase2-newsletter h2{
  font-family:'Fraunces',serif;
  font-size:clamp(1.9rem,4vw,3.2rem);
  line-height:1.05;
  letter-spacing:-.03em;
  color:#fff;
  margin-bottom:12px;
}
.dwj-phase2-newsletter p{
  max-width:560px;
  margin:0 auto 28px;
  color:rgba(255,255,255,.62);
}
.dwj-phase2-form{
  display:flex;
  justify-content:center;
  gap:10px;
  flex-wrap:wrap;
}
.dwj-phase2-form input{
  width:min(360px,100%);
  padding:13px 16px;
  border-radius:8px;
  border:1px solid rgba(255,255,255,.15);
  background:rgba(255,255,255,.08);
  color:#fff;
  outline:none;
}
.dwj-phase2-form input::placeholder{
  color:rgba(255,255,255,.38);
}
.dwj-phase2-form button{
  padding:13px 22px;
  border:0;
  border-radius:8px;
  background:#fff;
  color:var(--ink);
  font-weight:800;
  cursor:pointer;
}
.dwj-phase2-note{
  margin-top:12px!important;
  font-size:.76rem;
  color:rgba(255,255,255,.35)!important;
}

@media(max-width:1024px){
  .dwj-featured-box{grid-template-columns:1fr;}
  .dwj-featured-media,.dwj-featured-placeholder{min-height:280px;}
  .dwj-topic-hubs-grid{grid-template-columns:repeat(3,1fr);}
}
@media(max-width:768px){
  .dwj-phase2-section{padding:52px 20px;}
  .dwj-featured-content{padding:26px;}
  .dwj-topic-hubs-grid{grid-template-columns:repeat(2,1fr);}
}
@media(max-width:480px){
  .dwj-topic-hubs-grid{grid-template-columns:1fr;}
  .dwj-phase2-form{flex-direction:column;}
  .dwj-phase2-form input,.dwj-phase2-form button{width:100%;}
}


/* ==========================
   PHASE 3 ARTICLE PAGE UPGRADE
   Reading progress + read time + author box + related posts
========================== */

#dwjReadingProgress{
  position:fixed;
  top:0;
  left:0;
  width:0;
  height:3px;
  background:linear-gradient(90deg,var(--accent),var(--red));
  z-index:10000;
  transition:width .08s linear;
}

.dwj-read-time{
  font-family:'Space Mono',monospace;
  font-size:.76rem;
  color:var(--muted);
}

.dwj-author-box{
  margin:44px 0 0;
  padding:24px;
  border:1px solid var(--border);
  border-radius:18px;
  background:var(--off);
  display:grid;
  grid-template-columns:auto 1fr;
  gap:18px;
  align-items:start;
}

.dwj-author-avatar{
  width:64px;
  height:64px;
  border-radius:50%;
  display:flex;
  align-items:center;
  justify-content:center;
  background:linear-gradient(135deg,var(--accent),var(--red));
  color:#fff;
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:1.45rem;
  flex-shrink:0;
}

.dwj-author-name{
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:1.2rem;
  color:var(--ink);
  margin-bottom:4px;
}

.dwj-author-role{
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  color:var(--muted);
  text-transform:uppercase;
  letter-spacing:.08em;
  margin-bottom:10px;
}

.dwj-author-bio{
  color:var(--mid);
  font-size:.92rem;
  line-height:1.7;
  margin-bottom:14px;
}

.dwj-author-tags{
  display:flex;
  gap:7px;
  flex-wrap:wrap;
}

.dwj-author-tags span{
  font-family:'Space Mono',monospace;
  font-size:.64rem;
  color:var(--mid);
  border:1px solid var(--border);
  background:#fff;
  padding:4px 9px;
  border-radius:999px;
}

.dwj-article-tools{
  margin-top:28px;
  padding-top:24px;
  border-top:1px solid var(--border);
  display:flex;
  gap:10px;
  flex-wrap:wrap;
  align-items:center;
}

.dwj-article-tools-label{
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  color:var(--muted);
  text-transform:uppercase;
  letter-spacing:.08em;
  margin-right:4px;
}

.dwj-copy-link,
.dwj-mini-share{
  border:1px solid var(--border);
  background:#fff;
  color:var(--mid);
  border-radius:999px;
  padding:8px 13px;
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  font-weight:700;
  cursor:pointer;
  transition:.2s;
}

.dwj-copy-link:hover,
.dwj-mini-share:hover{
  border-color:var(--ink);
  color:var(--ink);
  background:var(--off);
}

.dwj-related-box{
  margin-top:44px;
  padding-top:36px;
  border-top:1px solid var(--border);
}

.dwj-related-head{
  display:flex;
  justify-content:space-between;
  align-items:flex-end;
  gap:16px;
  flex-wrap:wrap;
  margin-bottom:18px;
}

.dwj-related-title{
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:1.6rem;
  letter-spacing:-.02em;
  color:var(--ink);
}

.dwj-related-grid{
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:16px;
}

.dwj-related-card{
  display:block;
  border:1px solid var(--border);
  border-radius:14px;
  background:#fff;
  overflow:hidden;
  transition:.22s;
}

.dwj-related-card:hover{
  transform:translateY(-3px);
  box-shadow:var(--shadow);
}

.dwj-related-thumb{
  aspect-ratio:16/9;
  background:var(--off);
  overflow:hidden;
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:1.8rem;
}

.dwj-related-thumb img{
  width:100%;
  height:100%;
  object-fit:cover;
  margin:0!important;
  border-radius:0!important;
}

.dwj-related-body{
  padding:14px;
}

.dwj-related-cat{
  font-family:'Space Mono',monospace;
  font-size:.62rem;
  color:var(--accent);
  text-transform:uppercase;
  letter-spacing:.08em;
  margin-bottom:6px;
}

.dwj-related-card h3{
  font-family:'Fraunces',serif;
  font-size:1rem;
  line-height:1.35;
  margin:0;
  color:var(--ink);
}

.dwj-related-empty{
  border:1px dashed var(--border);
  border-radius:14px;
  padding:24px;
  color:var(--muted);
  font-family:'Space Mono',monospace;
  font-size:.72rem;
  text-align:center;
}

@media(max-width:768px){
  .dwj-author-box{
    grid-template-columns:1fr;
  }
  .dwj-related-grid{
    grid-template-columns:1fr;
  }
}


/* ==========================
   PHASE 4 SIDEBAR + MONETIZATION
   Sticky sidebar, quick search, resources, CTA boxes
========================== */

.dwj-layout-wrap{
  max-width:1160px;
  margin:0 auto;
  padding:0 20px;
}

.dwj-content-layout{
  display:grid;
  grid-template-columns:minmax(0,1fr) 320px;
  gap:28px;
  align-items:start;
}

.dwj-sidebar{
  position:sticky;
  top:84px;
  display:flex;
  flex-direction:column;
  gap:16px;
}

.dwj-side-card{
  background:#fff;
  border:1px solid var(--border);
  border-radius:16px;
  padding:18px;
  box-shadow:0 8px 28px rgba(0,0,0,.05);
}

.dwj-side-kicker{
  font-family:'Space Mono',monospace;
  font-size:.62rem;
  color:var(--muted);
  text-transform:uppercase;
  letter-spacing:.12em;
  margin-bottom:8px;
}

.dwj-side-title{
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:1.1rem;
  color:var(--ink);
  margin-bottom:12px;
}

.dwj-side-search{
  display:flex;
  gap:8px;
}

.dwj-side-search input{
  flex:1;
  min-width:0;
  border:1px solid var(--border);
  border-radius:8px;
  padding:10px 12px;
  font-size:.86rem;
  outline:none;
}

.dwj-side-search button{
  border:0;
  background:var(--ink);
  color:#fff;
  border-radius:8px;
  padding:10px 12px;
  cursor:pointer;
  font-weight:800;
}

.dwj-side-links{
  display:flex;
  flex-direction:column;
  gap:8px;
}

.dwj-side-link{
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:12px;
  border:1px solid var(--border);
  border-radius:10px;
  padding:10px 12px;
  font-size:.86rem;
  color:var(--mid);
  transition:.2s;
}

.dwj-side-link:hover{
  border-color:var(--ink);
  color:var(--ink);
  background:var(--off);
}

.dwj-side-link span:first-child{
  display:flex;
  align-items:center;
  gap:8px;
}

.dwj-side-newsletter{
  background:var(--ink);
  color:#fff;
  border-radius:16px;
  padding:20px;
  position:relative;
  overflow:hidden;
}

.dwj-side-newsletter::before{
  content:'';
  position:absolute;
  inset:0;
  background:
    radial-gradient(circle at 20% 20%,rgba(26,26,255,.25),transparent 35%),
    radial-gradient(circle at 80% 80%,rgba(255,58,45,.16),transparent 35%);
  pointer-events:none;
}

.dwj-side-newsletter > *{
  position:relative;
  z-index:1;
}

.dwj-side-newsletter h3{
  color:#fff;
  font-family:'Fraunces',serif;
  font-size:1.25rem;
  line-height:1.15;
  margin-bottom:8px;
}

.dwj-side-newsletter p{
  color:rgba(255,255,255,.58);
  font-size:.84rem;
  line-height:1.6;
  margin-bottom:14px;
}

.dwj-side-newsletter input{
  width:100%;
  border:1px solid rgba(255,255,255,.18);
  background:rgba(255,255,255,.08);
  color:#fff;
  border-radius:8px;
  padding:10px 12px;
  margin-bottom:8px;
  outline:none;
}

.dwj-side-newsletter input::placeholder{
  color:rgba(255,255,255,.38);
}

.dwj-side-newsletter button{
  width:100%;
  border:0;
  background:#fff;
  color:var(--ink);
  border-radius:8px;
  padding:10px 12px;
  font-weight:900;
  cursor:pointer;
}

.dwj-ad-box{
  min-height:250px;
  border:1px dashed var(--border);
  border-radius:16px;
  display:flex;
  align-items:center;
  justify-content:center;
  text-align:center;
  color:var(--muted);
  font-family:'Space Mono',monospace;
  font-size:.72rem;
  background:var(--off);
  padding:18px;
}

.dwj-resource-section{
  padding:72px 20px;
  background:#fff;
}

.dwj-resource-grid{
  max-width:1160px;
  margin:0 auto;
  display:grid;
  grid-template-columns:repeat(4,1fr);
  gap:16px;
}

.dwj-resource-card{
  border:1px solid var(--border);
  border-radius:16px;
  background:#fff;
  padding:22px;
  transition:.22s;
  box-shadow:0 8px 28px rgba(0,0,0,.04);
}

.dwj-resource-card:hover{
  transform:translateY(-4px);
  box-shadow:var(--shadow-h);
}

.dwj-resource-icon{
  width:44px;
  height:44px;
  border-radius:12px;
  display:flex;
  align-items:center;
  justify-content:center;
  background:var(--off);
  font-size:1.4rem;
  margin-bottom:14px;
}

.dwj-resource-card h3{
  font-family:'Fraunces',serif;
  font-size:1.08rem;
  color:var(--ink);
  margin-bottom:7px;
}

.dwj-resource-card p{
  color:var(--mid);
  font-size:.84rem;
  line-height:1.55;
  margin-bottom:12px;
}

.dwj-resource-card span{
  font-family:'Space Mono',monospace;
  color:var(--accent);
  font-size:.68rem;
  font-weight:800;
}

.dwj-inpost-cta{
  margin:36px 0;
  padding:22px;
  border:1px solid var(--border);
  border-radius:16px;
  background:
    radial-gradient(circle at 15% 15%,rgba(26,26,255,.06),transparent 35%),
    radial-gradient(circle at 85% 70%,rgba(255,58,45,.05),transparent 35%),
    var(--off);
}

.dwj-inpost-cta h3{
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:1.35rem;
  margin:0 0 8px;
  color:var(--ink);
}

.dwj-inpost-cta p{
  margin:0 0 14px;
  color:var(--mid);
  font-size:.94rem;
}

.dwj-inpost-cta a{
  display:inline-flex;
  padding:10px 16px;
  background:var(--ink);
  color:#fff!important;
  border-radius:8px;
  font-weight:800;
  font-size:.84rem;
  text-decoration:none!important;
}

@media(max-width:1024px){
  .dwj-content-layout{
    grid-template-columns:1fr;
  }
  .dwj-sidebar{
    position:static;
    display:grid;
    grid-template-columns:repeat(2,1fr);
  }
  .dwj-resource-grid{
    grid-template-columns:repeat(2,1fr);
  }
}

@media(max-width:680px){
  .dwj-sidebar,
  .dwj-resource-grid{
    grid-template-columns:1fr;
  }
}


/* ==========================
   PHASE 4 VISIBLE FIX
   Makes sidebar/resource blocks visible on homepage
========================== */

.dwj-phase4-visible{
