  .dwj-phase4-sidebar{
    grid-template-columns:1fr;
  }
}


/* ==========================
   SAFE LAYOUT EDITABLE ZONES
   Outside Blog1 only
========================== */

.layout-edit-zone{
  width:100%;
  max-width:1160px;
  margin:24px auto;
  padding:0 20px;
}

.layout-edit-zone .widget{
  margin:0 0 18px;
}

.layout-banner-box{
  min-height:96px;
  border:1.5px dashed var(--border);
  border-radius:16px;
  background:var(--off);
  color:var(--muted);
  display:flex;
  align-items:center;
  justify-content:center;
  text-align:center;
  padding:18px;
  font-family:'Space Mono',monospace;
  font-size:.72rem;
  line-height:1.6;
}

.layout-banner-box img,
.layout-edit-zone img{
  max-width:100%;
  height:auto;
  border-radius:14px;
}

body#layout .layout-edit-zone{
  display:block!important;
  max-width:100%!important;
  padding:10px!important;
  border:2px dashed #4f46e5!important;
  margin:10px!important;
  background:#f8fafc!important;
}


/* ==========================
   READY-MADE LAYOUT WIDGETS
   Default OFF widgets. Turn ON from Layout when needed.
========================== */
.dwj-layout-banner{
  width:100%;
}
.dwj-layout-banner a{
  display:block;
}
.dwj-layout-banner img{
  width:100%;
  height:auto;
  border-radius:16px;
  display:block;
}
.dwj-banner-wide img{
  max-height:320px;
  object-fit:cover;
}
.dwj-layout-cta{
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:22px;
  background:
    radial-gradient(circle at 15% 20%,rgba(26,26,255,.08),transparent 35%),
    radial-gradient(circle at 85% 70%,rgba(255,58,45,.07),transparent 35%),
    #ffffff;
  border:1px solid var(--border);
  border-radius:20px;
  padding:28px;
  box-shadow:0 12px 40px rgba(0,0,0,.06);
}
.dwj-layout-badge{
  display:inline-flex;
  font-family:'Space Mono',monospace;
  font-size:.65rem;
  text-transform:uppercase;
  letter-spacing:.1em;
  color:var(--accent);
  margin-bottom:8px;
}
.dwj-layout-cta h3{
  font-family:'Fraunces',serif;
  font-size:1.6rem;
  line-height:1.15;
  color:var(--ink);
  margin:0 0 8px;
}
.dwj-layout-cta p{
  color:var(--mid);
  margin:0;
}
.dwj-layout-cta a{
  white-space:nowrap;
  background:var(--ink);
  color:#fff!important;
  padding:12px 18px;
  border-radius:10px;
  font-weight:800;
}
@media(max-width:700px){
  .dwj-layout-cta{
    flex-direction:column;
    align-items:flex-start;
  }
  .dwj-layout-cta a{
    width:100%;
    text-align:center;
  }
}


/* ==========================
   PHASE 6 PUBLISHING FEATURES
   Breadcrumbs + TOC + Popular Articles + Meta Polish
========================== */

.dwj-breadcrumbs{
  max-width:720px;
  margin:calc(var(--nav-h) + 28px) auto -24px;
  padding:0 20px;
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  color:var(--muted);
  display:flex;
  align-items:center;
  gap:7px;
  flex-wrap:wrap;
}

.dwj-breadcrumbs a{
  color:var(--mid);
  transition:.2s;
}

.dwj-breadcrumbs a:hover{
  color:var(--accent);
}

.dwj-breadcrumbs span{
  color:var(--muted);
}

.dwj-toc-box{
  border:1px solid var(--border);
  background:var(--off);
  border-radius:16px;
  padding:18px;
  margin:28px 0;
}

.dwj-toc-head{
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:12px;
  cursor:pointer;
}

.dwj-toc-title{
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:1.15rem;
  color:var(--ink);
}

.dwj-toc-toggle{
  border:0;
  background:#fff;
  color:var(--ink);
  border-radius:999px;
  width:32px;
  height:32px;
  cursor:pointer;
  font-weight:900;
}

.dwj-toc-list{
  margin-top:14px;
  padding-left:0!important;
  list-style:none!important;
  display:flex;
  flex-direction:column;
  gap:8px;
}

.dwj-toc-list.hidden{
  display:none;
}

.dwj-toc-list a{
  display:block;
  color:var(--mid)!important;
  text-decoration:none!important;
  font-size:.9rem;
  line-height:1.5;
  border-left:2px solid var(--border);
  padding-left:10px;
  transition:.2s;
}

.dwj-toc-list a:hover{
  color:var(--accent)!important;
  border-left-color:var(--accent);
}

.dwj-toc-list .level-3{
  margin-left:18px;
  font-size:.84rem;
}

.dwj-toc-list .level-4{
  margin-left:34px;
  font-size:.8rem;
}

.dwj-floating-share{
  position:fixed;
  left:18px;
  top:50%;
  transform:translateY(-50%);
  z-index:600;
  display:flex;
  flex-direction:column;
  gap:8px;
}

.dwj-floating-share a,
.dwj-floating-share button{
  width:40px;
  height:40px;
  border-radius:50%;
  border:1px solid var(--border);
  background:#fff;
  color:var(--mid);
  display:flex;
  align-items:center;
  justify-content:center;
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  font-weight:900;
  cursor:pointer;
  box-shadow:0 6px 20px rgba(0,0,0,.08);
  transition:.2s;
}

.dwj-floating-share a:hover,
.dwj-floating-share button:hover{
  background:var(--ink);
  color:#fff;
  border-color:var(--ink);
}

.dwj-popular-section{
  padding:72px 20px;
  background:#fff;
}

.dwj-popular-wrap{
  max-width:1160px;
  margin:0 auto;
}

.dwj-popular-grid{
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:18px;
}

.dwj-popular-card{
  display:block;
  border:1px solid var(--border);
  border-radius:16px;
  background:#fff;
  overflow:hidden;
  box-shadow:0 10px 30px rgba(0,0,0,.05);
  transition:.22s;
}

.dwj-popular-card:hover{
  transform:translateY(-4px);
  box-shadow:var(--shadow-h);
}

.dwj-popular-thumb{
  aspect-ratio:16/9;
  background:var(--off);
  display:flex;
  align-items:center;
  justify-content:center;
  overflow:hidden;
  font-size:2rem;
}

.dwj-popular-thumb img{
  width:100%;
  height:100%;
  object-fit:cover;
}

.dwj-popular-body{
  padding:16px;
}

.dwj-popular-cat{
  font-family:'Space Mono',monospace;
  font-size:.62rem;
  color:var(--accent);
  text-transform:uppercase;
  letter-spacing:.08em;
  margin-bottom:7px;
}

.dwj-popular-card h3{
  font-family:'Fraunces',serif;
  font-size:1.08rem;
  line-height:1.35;
  color:var(--ink);
  margin:0 0 10px;
}

.dwj-popular-meta{
  font-family:'Space Mono',monospace;
  font-size:.64rem;
  color:var(--muted);
}

.dwj-meta-enhanced{
  font-weight:700;
}

@media(max-width:1024px){
  .dwj-floating-share{
    display:none;
  }
  .dwj-popular-grid{
    grid-template-columns:repeat(2,1fr);
  }
}

@media(max-width:680px){
  .dwj-popular-grid{
    grid-template-columns:1fr;
  }
  .dwj-breadcrumbs{
    margin-top:calc(var(--nav-h) + 18px);
  }
}


/* ==========================
   DUPLICATE SIDEBAR FIX
   Prevents old smart sidebar from appearing after footer.
========================== */
body > #dwjSmartSidebar,
footer + #dwjSmartSidebar,
.dwj-footer + #dwjSmartSidebar{
  display:none !important;
}


/* ==========================
   PHASE 7 RESOURCE PAGE SYSTEM
   Use these classes inside Blogger Pages.
   Page content stays clean; theme handles styling.
========================== */

.dwj-resource-page{
  --rp-ink:var(--ink,#0a0a0a);
  --rp-mid:var(--mid,#525250);
  --rp-muted:var(--muted,#888884);
  --rp-off:var(--off,#f8f8f6);
  --rp-border:var(--border,#e6e6e3);
  --rp-accent:var(--accent,#1a1aff);
  width:100%;
}

.dwj-rp-wrap{
  width:100%;
  max-width:1160px;
  margin:0 auto;
  padding:0 20px;
}

.dwj-rp-hero{
  padding:76px 0 52px;
  background:
    radial-gradient(circle at 12% 18%,rgba(26,26,255,.08),transparent 32%),
    radial-gradient(circle at 88% 76%,rgba(255,58,45,.06),transparent 32%),
    #fff;
  border-bottom:1px solid var(--rp-border);
}

.dwj-rp-kicker{
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  text-transform:uppercase;
  letter-spacing:.12em;
  color:var(--rp-muted);
  margin-bottom:10px;
}

.dwj-rp-title{
  font-family:'Fraunces',serif;
  font-size:clamp(2.3rem,6vw,4.8rem);
  line-height:1.02;
  letter-spacing:-.04em;
  color:var(--rp-ink);
  margin:0;
}

.dwj-rp-title span{
  color:var(--rp-accent);
}

.dwj-rp-desc{
  max-width:760px;
  margin:18px 0 0;
  color:var(--rp-mid);
  font-size:1.05rem;
  line-height:1.8;
}

.dwj-rp-actions{
  display:flex;
  gap:12px;
  flex-wrap:wrap;
  margin-top:28px;
}

.dwj-rp-btn{
  display:inline-flex;
  align-items:center;
  justify-content:center;
  padding:12px 22px;
  border-radius:9px;
  font-weight:850;
  font-size:.9rem;
  text-decoration:none!important;
}

.dwj-rp-btn-dark{
  background:var(--rp-ink);
  color:#fff!important;
}

.dwj-rp-btn-light{
  border:1px solid var(--rp-border);
  color:var(--rp-mid)!important;
  background:#fff;
}

.dwj-rp-section{
  padding:64px 0;
}

.dwj-rp-section.off{
  background:var(--rp-off);
  border-top:1px solid var(--rp-border);
  border-bottom:1px solid var(--rp-border);
}

.dwj-rp-head{
  display:flex;
  align-items:flex-end;
  justify-content:space-between;
  gap:18px;
  flex-wrap:wrap;
  margin-bottom:28px;
}

.dwj-rp-heading{
  font-family:'Fraunces',serif;
  font-size:clamp(1.8rem,3vw,2.7rem);
  line-height:1.08;
  letter-spacing:-.03em;
  color:var(--rp-ink);
  margin:0;
}

.dwj-rp-sub{
  color:var(--rp-mid);
  margin:8px 0 0;
  max-width:650px;
  line-height:1.7;
}

.dwj-rp-grid{
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:18px;
}

.dwj-rp-grid.two{
  grid-template-columns:repeat(2,1fr);
}

.dwj-rp-grid.four{
  grid-template-columns:repeat(4,1fr);
}

.dwj-rp-card{
  background:#fff;
  border:1px solid var(--rp-border);
  border-radius:18px;
  padding:22px;
  box-shadow:0 10px 30px rgba(0,0,0,.05);
  transition:.22s;
  display:flex;
  flex-direction:column;
  min-height:230px;
}

.dwj-rp-card:hover{
  transform:translateY(-4px);
  box-shadow:0 18px 44px rgba(0,0,0,.09);
}

.dwj-rp-icon{
  width:48px;
  height:48px;
  border-radius:14px;
  display:flex;
  align-items:center;
  justify-content:center;
  background:var(--rp-off);
  font-size:1.5rem;
  margin-bottom:14px;
}

.dwj-rp-card h3{
  font-family:'Fraunces',serif;
  font-size:1.2rem;
  color:var(--rp-ink);
  margin:0 0 8px;
}

.dwj-rp-tag{
  display:inline-flex;
  width:max-content;
  font-family:'Space Mono',monospace;
  font-size:.62rem;
  text-transform:uppercase;
  letter-spacing:.08em;
  color:var(--rp-accent);
  margin-bottom:10px;
}

.dwj-rp-card p{
  color:var(--rp-mid);
  font-size:.9rem;
  line-height:1.65;
  margin:0 0 14px;
}

.dwj-rp-meta{
  display:flex;
  gap:7px;
  flex-wrap:wrap;
  margin-top:auto;
  margin-bottom:16px;
}

.dwj-rp-meta span{
  font-family:'Space Mono',monospace;
  font-size:.62rem;
  color:var(--rp-muted);
  border:1px solid var(--rp-border);
  border-radius:999px;
  padding:4px 8px;
}

.dwj-rp-link{
  display:inline-flex;
  justify-content:center;
  padding:10px 14px;
  border-radius:8px;
  background:var(--rp-ink);
  color:#fff!important;
  font-weight:850;
  font-size:.84rem;
  text-decoration:none!important;
}

.dwj-rp-link.light{
  background:#fff;
  border:1px solid var(--rp-border);
  color:var(--rp-ink)!important;
}

.dwj-rp-directory{
  display:grid;
  grid-template-columns:repeat(4,1fr);
  gap:14px;
}

.dwj-rp-dir-card{
  background:#fff;
  border:1px solid var(--rp-border);
  border-radius:16px;
  padding:18px;
  min-height:150px;
  display:block;
  transition:.2s;
}

.dwj-rp-dir-card:hover{
  transform:translateY(-3px);
  background:var(--rp-off);
}

.dwj-rp-dir-card strong{
  display:block;
  font-family:'Fraunces',serif;
  font-size:1.05rem;
  color:var(--rp-ink);
  margin:8px 0 6px;
}

.dwj-rp-dir-card p{
  color:var(--rp-mid);
  font-size:.84rem;
  line-height:1.55;
  margin:0;
}

.dwj-rp-table{
  width:100%;
  border-collapse:collapse;
  background:#fff;
  border:1px solid var(--rp-border);
  border-radius:16px;
  overflow:hidden;
}

.dwj-rp-table th,
.dwj-rp-table td{
  border-bottom:1px solid var(--rp-border);
  padding:14px;
  text-align:left;
  font-size:.9rem;
}

.dwj-rp-table th{
  background:var(--rp-off);
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  text-transform:uppercase;
  color:var(--rp-muted);
}

.dwj-rp-table tr:last-child td{
  border-bottom:0;
}

.dwj-rp-cta{
  background:var(--rp-ink);
  color:#fff;
  border-radius:24px;
  padding:42px;
  display:grid;
  grid-template-columns:1.2fr .8fr;
  gap:24px;
  align-items:center;
}

.dwj-rp-cta h2{
  font-family:'Fraunces',serif;
  font-size:clamp(1.8rem,3vw,2.8rem);
  line-height:1.08;
  color:#fff;
  margin:0 0 10px;
}

.dwj-rp-cta p{
  color:rgba(255,255,255,.7);
  margin:0;
  line-height:1.7;
}

.dwj-rp-cta a{
  justify-self:end;
  background:#fff;
  color:var(--rp-ink)!important;
  padding:13px 22px;
  border-radius:9px;
  font-weight:900;
  text-decoration:none!important;
}

.dwj-rp-note{
  color:var(--rp-muted);
  font-size:.78rem;
  line-height:1.6;
  margin-top:22px;
}

@media(max-width:1024px){
  .dwj-rp-grid,
  .dwj-rp-grid.two,
  .dwj-rp-grid.four{
    grid-template-columns:repeat(2,1fr);
  }
  .dwj-rp-directory{
    grid-template-columns:repeat(2,1fr);
  }
}

@media(max-width:700px){
  .dwj-rp-grid,
  .dwj-rp-grid.two,
  .dwj-rp-grid.four,
  .dwj-rp-directory{
    grid-template-columns:1fr;
  }
  .dwj-rp-cta{
    grid-template-columns:1fr;
  }
  .dwj-rp-cta a{
    justify-self:start;
  }
  .dwj-rp-table{
    display:block;
    overflow-x:auto;
  }
}


/* ==========================
   STATIC PAGE FIX
   Normal Blogger Pages now show their own content.
========================== */
.dwj-static-page-wrap{
  max-width:100%;
}
.dwj-static-page-wrap .dwj-post-title{
  display:none;
}
.dwj-static-page-wrap .dwj-post-body{
  padding:0;
}
.dwj-static-page-wrap .dwj-post-body > .dwj-resource-page{
  margin-top:calc(var(--nav-h) * -1);
}


/* ==========================
   ARCHIVE FEED OVERRIDE FIX
   /search and label pages now load up to 50 posts from feed.
========================== */
.dwj-archive-feed-note{
  grid-column:1/-1;
  text-align:center;
  padding:34px 20px;
  color:var(--muted);
  font-family:'Space Mono',monospace;
  font-size:.78rem;
}


/* ==========================
   ARCHIVE CARD DESIGN FIX
   Full-width thumbnails like premium blog cards.
========================== */

.dwj-posts-grid,
#latest .dwj-posts-grid{
  align-items:stretch;
}

.dwj-card{
  overflow:hidden !important;
  padding:0 !important;
  border-radius:18px !important;
  background:#fff !important;
  border:1px solid var(--border) !important;
  box-shadow:0 10px 32px rgba(0,0,0,.05) !important;
  display:flex !important;
  flex-direction:column !important;
}

.dwj-card:hover{
  transform:translateY(-4px);
  box-shadow:0 18px 44px rgba(0,0,0,.09) !important;
}

.dwj-card-media{
  width:100% !important;
  aspect-ratio:16/9 !important;
  min-height:0 !important;
  height:auto !important;
  background:linear-gradient(135deg,#eef2ff,#f8f8f6) !important;
  overflow:hidden !important;
  display:block !important;
  border-radius:0 !important;
}

.dwj-card-media img{
  width:100% !important;
  height:100% !important;
  object-fit:cover !important;
  object-position:center !important;
  display:block !important;
  border-radius:0 !important;
  margin:0 !important;
}

.dwj-card-ph{
  width:100%;
  height:100%;
  min-height:220px;
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:2.4rem;
  background:
    radial-gradient(circle at 20% 20%,rgba(26,26,255,.10),transparent 35%),
    radial-gradient(circle at 80% 70%,rgba(255,58,45,.08),transparent 35%),
    #f0f2f7;
}

.dwj-card-body{
  padding:24px !important;
  display:flex !important;
  flex-direction:column !important;
  flex:1 !important;
}

.dwj-card-title{
  font-size:1.35rem !important;
  line-height:1.28 !important;
  margin:0 0 12px !important;
}

.dwj-card-snip{
  font-size:.98rem !important;
  line-height:1.65 !important;
  color:var(--mid) !important;
  display:-webkit-box;
  -webkit-line-clamp:3;
  -webkit-box-orient:vertical;
  overflow:hidden;
  margin-bottom:18px !important;
}

.dwj-card-date{
  margin-top:auto !important;
}

/* force images inside feed-rendered archive cards not to become tiny */
.dwj-posts-grid .dwj-card img,
#latest .dwj-card img{
  max-width:none !important;
}

/* responsive */
@media(max-width:760px){
  .dwj-card-body{
    padding:20px !important;
  }
  .dwj-card-title{
    font-size:1.2rem !important;
  }
}


/* ==========================
   FINAL CLEANUP PATCH
   Light mode only + old dark mode neutralized
========================== */
.dwj-theme-toggle,
#dwjThemeToggle{
  display:none!important;
}

body.dwj-dark,
body.dark-mode{
  background:var(--white)!important;
  color:var(--ink)!important;
}

body.dwj-dark *,
body.dark-mode *{
  color:inherit;
}


/* ==========================
   BLANK IN-ARTICLE AD FIX
   Hide empty ad box until real ad/banner code is added.
========================== */
.dwj-ad-inarticle:empty{
  display:none !important;
  min-height:0 !important;
  padding:0 !important;
  margin:0 !important;
  border:0 !important;
}

.dwj-ad-inarticle{
  display:none !important;
}

.dwj-ad-inarticle.has-ad,
.dwj-ad-inarticle:has(ins),
.dwj-ad-inarticle:has(iframe),
.dwj-ad-inarticle:has(img),
.dwj-ad-inarticle:has(script){
  display:flex !important;
}


/* ==========================
   FORCE REMOVE IN-ARTICLE AD BOX
   Ads are disabled until you manually add AdSense later.
========================== */
.dwj-ad-inarticle,
.dwj-ad-inarticle *,
div[class*="dwj-ad-inarticle"],
section[class*="dwj-ad-inarticle"]{
  display:none !important;
  visibility:hidden !important;
  height:0 !important;
  min-height:0 !important;
  max-height:0 !important;
  padding:0 !important;
  margin:0 !important;
  border:0 !important;
  overflow:hidden !important;
}


/* Keep Jai Jain signature visible inside posts */
.dwj-post-body a[href*="jaijain"],
.dwj-post-body a[href*="Jai"],
.dwj-post-body strong,
.dwj-post-body b{
  visibility:visible !important;
}


/* ==========================
   DECODE WITH JAI v1.0 FINAL PATCH
   Final nav/footer/legal links + light-only cleanup.
========================== */

.dwj-theme-toggle,
#dwjThemeToggle{
  display:none!important;
}

body.dwj-dark,
body.dark-mode{
  background:var(--white)!important;
  color:var(--ink)!important;
}

.dwj-ad-inarticle,
div[class*="dwj-ad-inarticle"],
section[class*="dwj-ad-inarticle"]{
  display:none!important;
  height:0!important;
  min-height:0!important;
  padding:0!important;
  margin:0!important;
  border:0!important;
  overflow:hidden!important;
}

.dwj-footer-grid{
  grid-template-columns:1.25fr 1fr 1fr 1fr;
}

.dwj-footer-ul li{
  list-style:none;
}

.dwj-footer-ul a{
  display:inline-block;
}

@media(max-width:900px){
  .dwj-footer-grid{
    grid-template-columns:1fr 1fr;
  }
}

@media(max-width:560px){
  .dwj-footer-grid{
    grid-template-columns:1fr;
  }
}


/* ==========================
   LIVE FIX: POPULAR + CARD IMAGES RESTORE
   Restores premium archive cards and branded default thumbnails.
========================== */

.dwj-theme-toggle,
#dwjThemeToggle{
  display:none!important;
}

.dwj-ad-inarticle,
div[class*="dwj-ad-inarticle"],
section[class*="dwj-ad-inarticle"]{
  display:none!important;
  height:0!important;
  min-height:0!important;
  padding:0!important;
  margin:0!important;
  border:0!important;
  overflow:hidden!important;
}

.dwj-default-thumb{
  width:100%;
  height:100%;
  min-height:220px;
  aspect-ratio:16/9;
  display:flex;
  align-items:center;
  justify-content:center;
  position:relative;
  overflow:hidden;
  background:
    radial-gradient(circle at 18% 20%, rgba(139,92,246,.38), transparent 30%),
    radial-gradient(circle at 85% 78%, rgba(59,130,246,.34), transparent 34%),
    linear-gradient(135deg,#08142B 0%,#0f172a 55%,#1e1b4b 100%);
}

.dwj-default-thumb::before{
  content:"";
  position:absolute;
  inset:0;
  background-image:
    linear-gradient(rgba(255,255,255,.06) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,.06) 1px, transparent 1px);
  background-size:34px 34px;
  opacity:.42;
}

.dwj-default-thumb-inner{
  position:relative;
  z-index:2;
  text-align:center;
  padding:22px;
  color:#fff;
}

.dwj-default-thumb-logo{
  width:58px;
  height:58px;
  margin:0 auto 14px;
  border-radius:18px;
  display:flex;
  align-items:center;
  justify-content:center;
  background:rgba(255,255,255,.10);
  border:1px solid rgba(255,255,255,.18);
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:2rem;
  color:#fff;
  box-shadow:0 18px 45px rgba(0,0,0,.22);
}

.dwj-default-thumb-title{
  font-family:'Fraunces',serif;
  font-weight:900;
  font-size:clamp(1.35rem,2.2vw,2.15rem);
  line-height:1;
  letter-spacing:-.03em;
  color:#fff;
  margin-bottom:10px;
}

.dwj-default-thumb-sub{
  font-family:'Space Mono',monospace;
  font-size:.68rem;
  letter-spacing:.12em;
  text-transform:uppercase;
  color:rgba(255,255,255,.72);
}

.dwj-card{
  overflow:hidden!important;
  padding:0!important;
  border-radius:18px!important;
  background:#fff!important;
  border:1px solid var(--border)!important;
  box-shadow:0 10px 32px rgba(0,0,0,.05)!important;
  display:flex!important;
  flex-direction:column!important;
}

.dwj-card-media,
.dwj-card-thumb,
.dwj-popular-thumb,
.dwj-related-thumb,
.dwj-pro-related-thumb{
  width:100%!important;
  aspect-ratio:16/9!important;
  min-height:0!important;
  height:auto!important;
  background:#08142B!important;
  overflow:hidden!important;
  display:block!important;
  border-radius:0!important;
}

.dwj-card-media img,
.dwj-card-thumb img,
.dwj-popular-thumb img,
.dwj-related-thumb img,
.dwj-pro-related-thumb img{
  width:100%!important;
  height:100%!important;
  object-fit:cover!important;
  object-position:center!important;
  display:block!important;
  border-radius:0!important;
  margin:0!important;
}

.dwj-card-ph{
  width:100%!important;
  aspect-ratio:16/9!important;
  background:none!important;
  font-size:0!important;
  display:block!important;
}

.dwj-card-body{
  padding:24px!important;
  display:flex!important;
  flex-direction:column!important;
  flex:1!important;
}

.dwj-card-title{
  font-size:1.35rem!important;
  line-height:1.28!important;
  margin:0 0 12px!important;
}

.dwj-card-snip{
  font-size:.98rem!important;
  line-height:1.65!important;
  color:var(--mid)!important;
  display:-webkit-box;
  -webkit-line-clamp:3;
  -webkit-box-orient:vertical;
  overflow:hidden;
  margin-bottom:18px!important;
}

.dwj-card-date{
  margin-top:auto!important;
}

.dwj-popular-grid{
  display:grid!important;
  grid-template-columns:repeat(3,1fr)!important;
  gap:18px!important;
}

.dwj-popular-card{
  display:block!important;
  border:1px solid var(--border)!important;
  border-radius:18px!important;
  background:#fff!important;
  overflow:hidden!important;
  box-shadow:0 10px 30px rgba(0,0,0,.05)!important;
  transition:.22s!important;
}

.dwj-popular-card:hover{
  transform:translateY(-4px)!important;
  box-shadow:0 18px 44px rgba(0,0,0,.09)!important;
}

.dwj-popular-body{
  padding:18px!important;
}

.dwj-popular-cat{
  font-family:'Space Mono',monospace!important;
  font-size:.62rem!important;
  color:var(--accent)!important;
  text-transform:uppercase!important;
  letter-spacing:.08em!important;
  margin-bottom:7px!important;
}

.dwj-popular-card h3{
  font-family:'Fraunces',serif!important;
  font-size:1.1rem!important;
  line-height:1.35!important;
  color:var(--ink)!important;
  margin:0 0 10px!important;
}

.dwj-popular-meta{
  font-family:'Space Mono',monospace!important;
  font-size:.64rem!important;
  color:var(--muted)!important;
}

@media(max-width:1024px){
  .dwj-popular-grid{
    grid-template-columns:repeat(2,1fr)!important;
  }
}

@media(max-width:680px){
  .dwj-popular-grid{
    grid-template-columns:1fr!important;
  }
  .dwj-card-body{
    padding:20px!important;
  }
  .dwj-card-title{
    font-size:1.2rem!important;
  }
}

body.script:
//
/* Dark mode removed: light mode only */

/* Back to top */
var btt=document.getElementById('dwj-btt');
if(btt){
  window.addEventListener('scroll',function(){btt.classList.toggle('show',window.scrollY>400);},{passive:true});
  btt.addEventListener('click',function(){window.scrollTo({top:0,behavior:'smooth'});});
}

/* Mobile hamburger menu */
var ham=document.getElementById('dwjHam'),mob=document.getElementById('dwjMob');
if(ham&&mob){
  ham.addEventListener('click',function(){
    var o=mob.classList.toggle('open');
    ham.classList.toggle('open',o);
    ham.setAttribute('aria-label',o?'Close menu':'Open menu');
    ham.setAttribute('aria-expanded',String(o));
  });
  mob.querySelectorAll('a').forEach(function(a){
    a.addEventListener('click',function(){
      mob.classList.remove('open');
      ham.classList.remove('open');
      ham.setAttribute('aria-label','Open menu');
      ham.setAttribute('aria-expanded','false');
    });
  });
  document.addEventListener('click',function(e){
    if(!ham.contains(e.target)&&!mob.contains(e.target)){
      mob.classList.remove('open');
      ham.classList.remove('open');
      ham.setAttribute('aria-label','Open menu');
      ham.setAttribute('aria-expanded','false');
    }
  });
}

/* ============================================================
   FIX 2: Newsletter — real form submission to Google Apps Script
   Replace YOUR_APPS_SCRIPT_URL with your deployed Web App URL.
   See setup instructions in the HTML comment above the newsletter section.
   ============================================================ */
var APPS_SCRIPT_URL = 'YOUR_APPS_SCRIPT_URL';

var nlBtn=document.getElementById('dwjNlBtn');
var nlMsg=document.getElementById('dwjNlMsg');

if(nlBtn){
  nlBtn.addEventListener('click',function(){
    var input=document.getElementById('dwjEmail');
    if(!input||!input.value||!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(input.value)){
      if(nlMsg){nlMsg.textContent='Please enter a valid email.';nlMsg.style.color='#ff3a2d';}
      return;
    }

    nlBtn.disabled=true;
    nlBtn.textContent='Subscribing...';

    fetch(APPS_SCRIPT_URL,{
      method:'POST',
      mode:'no-cors',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({email:input.value})
    })
    .then(function(){
      if(nlMsg){nlMsg.textContent='\u2713 You\'re in! Check your inbox.';nlMsg.style.color='#00c48c';}
      input.value='';
      nlBtn.textContent='Subscribed \u2713';
    })
    .catch(function(){
      if(nlMsg){nlMsg.textContent='Something went wrong. Try again.';nlMsg.style.color='#ff3a2d';}
      nlBtn.disabled=false;
      nlBtn.textContent='Subscribe \u2192';
    });
  });
}

//

//
/* LIGHT MODE ONLY FORCE */
(function(){
  try{
    document.body.classList.remove('dark-mode');
    document.body.classList.remove('dark');
    localStorage.removeItem('dwjTheme');
    localStorage.removeItem('theme');
  }catch(e){}
})();
//

//
(function(){
  var box = document.getElementById('dwjFeaturedBox');
  if(!box) return;

  var BLOG = '<data:blog.homepageUrl/>'.replace(/\/$/,'');

  function esc(s){
    return String(s || '').replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }

  function getUrl(e){
    if(!e.link) return '#';
    for(var i=0;i<e.link.length;i++){
      if(e.link[i].rel === 'alternate') return e.link[i].href;
    }
    return '#';
  }

  function getThumb(e){
    if(e.content && e.content.$t){
      var match = e.content.$t.match(/<img[^>]+src=["']([^"']+)["']/i);
      if(match) return match[1].replace(/\/s\d+(-c)?\//, '/s1600/');
    }
    if(e.media$thumbnail && e.media$thumbnail.url){
      return e.media$thumbnail.url.replace(/\/s\d+(-c)?\//, '/s1600/');
    }
    return '';
  }

  function getSnippet(e){
    var raw = '';
    if(e.summary && e.summary.$t) raw = e.summary.$t;
    else if(e.content && e.content.$t){
      var d = document.createElement('div');
      d.innerHTML = e.content.$t;
      raw = d.textContent || d.innerText || '';
    }
    raw = raw.replace(/\s+/g,' ').trim();
    return raw.slice(0,180) + (raw.length > 180 ? '...' : '');
  }

  function getCat(e){
    return (e.category && e.category[0]) ? e.category[0].term : 'Featured';
  }

  window.dwjFeaturedFeed = function(data){
    var entries = data && data.feed && data.feed.entry ? data.feed.entry : [];
    if(!entries.length){
      box.innerHTML = '<div class="dwj-featured-empty">No Featured post found. Add label <strong>Featured</strong> to one post.</div>';
      return;
    }

    var e = entries[0];
    var title = e.title && e.title.$t ? e.title.$t : 'Decode With Jai';
    var url = getUrl(e);
    var thumb = getThumb(e);
    var snip = getSnippet(e);
    var cat = getCat(e);

    box.innerHTML =
      '<article class="dwj-featured-box">' +
        '<a class="dwj-featured-media" href="'+esc(url)+'">' +
          (thumb ? '<img alt="'+esc(title)+'" loading="lazy" src="'+esc(thumb)+'"/>' : '<div class="dwj-featured-placeholder">⭐</div>') +
        '</a>' +
        '<div class="dwj-featured-content">' +
          '<div class="dwj-featured-badge">⭐ Featured Guide</div>' +
          '<div class="dwj-featured-cat">'+esc(cat)+'</div>' +
          '<h3 class="dwj-featured-title"><a href="'+esc(url)+'">'+esc(title)+'</a></h3>' +
          '<p class="dwj-featured-snip">'+esc(snip)+'</p>' +
          '<a class="dwj-featured-btn" href="'+esc(url)+'">Read Full Guide →</a>' +
        '</div>' +
      '</article>';
  };

  var script = document.createElement('script');
  script.src = BLOG + '/feeds/posts/summary/-/Featured?alt=json-in-script&max-results=1&callback=dwjFeaturedFeed';
  script.onerror = function(){
    box.innerHTML = '<div class="dwj-featured-empty">Featured article could not load. Check blog feed settings.</div>';
  };
  document.head.appendChild(script);
})();
//

//
(function(){
  var tries = 0;
  function checkFeatured(){
    var box = document.getElementById('dwjFeaturedBox');
    if(!box) return;

    var text = (box.textContent || '').trim().toLowerCase();
    if(text.indexOf('loading featured article') === -1) return;

    tries++;
    if(tries < 6){
      setTimeout(checkFeatured, 1000);
      return;
    }

    box.innerHTML = '<div class="dwj-featured-empty">Featured post not loading from feed yet. Make sure:<br/><br/>1. Post label is exactly <strong>Featured</strong><br/>2. Blogger Settings → Site feed → Allow blog feed = <strong>Full</strong><br/>3. Wait 1-2 minutes after adding the label, then refresh.</div>';
  }
  setTimeout(checkFeatured, 1500);
})();
//

//
(function(){
  function ready(fn){
    if(document.readyState !== 'loading') fn();
    else document.addEventListener('DOMContentLoaded', fn);
  }

  ready(function(){
    var box = document.getElementById('dwjFeaturedBox');
    if(!box) return;

    function clean(s){
      return String(s || '').replace(/\s+/g,' ').trim();
    }

    function makeFeaturedFromCard(card){
      if(!card) return false;

      var linkEl = card.matches('a') ? card : card.querySelector('a[href]');
      var url = linkEl ? linkEl.href : '/search/label/Featured';

      var titleEl = card.querySelector('.dwj-card-title, h3, .post-title, h2, a');
      var title = clean(titleEl ? titleEl.textContent : 'Featured Article');

      var imgEl = card.querySelector('img');
      var img = imgEl ? imgEl.src : '';

      var snipEl = card.querySelector('.dwj-card-snip, .snippet, .post-snippet, p');
      var snip = clean(snipEl ? snipEl.textContent : 'Read this featured guide from Decode With Jai.');

      var catEl = card.querySelector('.dwj-card-cat, .post-cat');
      var cat = clean(catEl ? catEl.textContent : 'Featured');

      box.innerHTML =
        '<article class="dwj-featured-box">' +
          '<a class="dwj-featured-media" href="'+url+'">' +
            (img ? '<img alt="'+title.replace(/"/g,'&quot;')+'" loading="lazy" src="'+img+'"/>' : '<div class="dwj-featured-placeholder">⭐</div>') +
          '</a>' +
          '<div class="dwj-featured-content">' +
            '<div class="dwj-featured-badge">⭐ Featured Guide</div>' +
            '<div class="dwj-featured-cat">'+cat+'</div>' +
            '<h3 class="dwj-featured-title"><a href="'+url+'">'+title+'</a></h3>' +
            '<p class="dwj-featured-snip">'+snip+'</p>' +
            '<a class="dwj-featured-btn" href="'+url+'">Read Full Guide →</a>' +
          '</div>' +
        '</article>';
      return true;
    }

    function loadFromFeaturedLabelPage(){
      var url = '/search/label/Featured';
      fetch(url, {credentials:'same-origin'})
        .then(function(r){ return r.text(); })
        .then(function(html){
          var doc = new DOMParser().parseFromString(html, 'text/html');

          var card =
            doc.querySelector('.dwj-card') ||
            doc.querySelector('.post') ||
            doc.querySelector('article') ||
            doc.querySelector('.post-outer');

          if(!makeFeaturedFromCard(card)){
            box.innerHTML = '<div class="dwj-featured-empty">No Featured post found. Add label <strong>Featured</strong> to one published post.</div>';
          }
        })
        .catch(function(){
          box.innerHTML = '<div class="dwj-featured-empty">Featured post could not load automatically. Use the View Featured link or check that the post label is exactly <strong>Featured</strong>.</div>';
        });
    }

    // Wait a moment. If old feed loader succeeds, don't touch it.
    setTimeout(function(){
      var txt = clean(box.textContent).toLowerCase();
      if(
        txt.indexOf('loading featured article') > -1 ||
        txt.indexOf('featured article could not load') > -1 ||
        txt.indexOf('featured post not loading') > -1 ||
        txt.indexOf('no featured post found') > -1
      ){
        loadFromFeaturedLabelPage();
      }
    }, 1800);
  });
})();
//

//
(function(){
  // Reading progress
  var bar = document.getElementById('dwjReadingProgress');
  if(!bar){
    bar = document.createElement('div');
    bar.id = 'dwjReadingProgress';
    document.body.appendChild(bar);
  }

  window.addEventListener('scroll', function(){
    var doc = document.documentElement;
    var max = doc.scrollHeight - doc.clientHeight;
    var pct = max ? (doc.scrollTop / max) * 100 : 0;
    bar.style.width = pct + '%';
  });

  // Reading time
  var body = document.querySelector('.dwj-post-body');
  var meta = document.querySelector('.dwj-post-meta');
  if(body && meta && !document.getElementById('dwjReadTime')){
    var text = body.innerText || '';
    var words = text.trim().split(/\s+/).filter(Boolean).length;
    var mins = Math.max(1, Math.ceil(words / 220));
    var sep = document.createElement('span');
    sep.innerHTML = '&#183;';
    var rt = document.createElement('span');
    rt.className = 'dwj-read-time';
    rt.id = 'dwjReadTime';
    rt.textContent = mins + ' min read';
    meta.appendChild(sep);
    meta.appendChild(rt);
  }

  // Share links
  var title = document.title || 'Decode With Jai';
  var url = location.href;
  var x = document.getElementById('dwjShareX');
  var li = document.getElementById('dwjShareLinkedIn');
  var wa = document.getElementById('dwjShareWhatsApp');
  if(x) x.href = 'https://twitter.com/intent/tweet?url=' + encodeURIComponent(url) + '&text=' + encodeURIComponent(title);
  if(li) li.href = 'https://www.linkedin.com/shareArticle?mini=true&url=' + encodeURIComponent(url) + '&title=' + encodeURIComponent(title);
  if(wa) wa.href = 'https://api.whatsapp.com/send?text=' + encodeURIComponent(title + ' ' + url);

  var copy = document.getElementById('dwjCopyLink');
  if(copy){
    copy.addEventListener('click', function(){
      navigator.clipboard.writeText(url).then(function(){
        copy.textContent = 'Copied!';
        setTimeout(function(){ copy.textContent = 'Copy Link'; }, 1600);
      }).catch(function(){
        copy.textContent = 'Copy URL Manually';
      });
    });
  }

  // Related posts from current category label page
  var grid = document.getElementById('dwjRelatedGrid');
  if(!grid || !body) return;

  function clean(s){ return String(s || '').replace(/\s+/g,' ').trim(); }

  var catEl = document.querySelector('.dwj-post-cat');
  var label = catEl ? clean(catEl.textContent) : '';
  if(!label){
    grid.innerHTML = '<div class="dwj-related-empty">No category found for related articles.</div>';
    return;
  }

  function makeCard(card){
    if(!card) return '';
    var linkEl = card.matches && card.matches('a') ? card : card.querySelector('a[href]');
    var href = linkEl ? linkEl.href : '#';
    if(href === location.href) return '';

    var titleEl = card.querySelector('.dwj-card-title, h3, .post-title, h2, a');
    var t = clean(titleEl ? titleEl.textContent : 'Related Article');
    if(!t) return '';

    var imgEl = card.querySelector('img');
    var img = imgEl ? imgEl.src : '';

    var catCardEl = card.querySelector('.dwj-card-cat, .post-cat');
    var c = clean(catCardEl ? catCardEl.textContent : label);

    return '<a class="dwj-related-card" href="'+href+'">' +
      '<div class="dwj-related-thumb">' + (img ? '<img alt="'+t.replace(/"/g,'&quot;')+'" loading="lazy" src="'+img+'"/>' : '📘') + '</div>' +
      '<div class="dwj-related-body">' +
        '<div class="dwj-related-cat">'+c+'</div>' +
        '<h3>'+t+'</h3>' +
      '</div>' +
    '</a>';
  }

  fetch('/search/label/' + encodeURIComponent(label), {credentials:'same-origin'})
    .then(function(r){ return r.text(); })
    .then(function(html){
      var doc = new DOMParser().parseFromString(html, 'text/html');
      var cards = Array.prototype.slice.call(doc.querySelectorAll('.dwj-card, article, .post, .post-outer'));
      var out = '';
      for(var i=0; i<cards.length && out.split('dwj-related-card').length <= 3; i++){
        out += makeCard(cards[i]);
      }
      grid.innerHTML = out || '<div class="dwj-related-empty">No related articles found yet.</div>';
    })
    .catch(function(){
      grid.innerHTML = '<div class="dwj-related-empty">Related articles could not load.</div>';
    });
})();
//

//
(function(){
  function clean(s){ return String(s || '').replace(/\s+/g,' ').trim(); }

  /* Breadcrumbs */
  var postWrap = document.querySelector('.dwj-post-wrap');
  var postTitle = document.querySelector('.dwj-post-title');
  if(postWrap && postTitle && !document.querySelector('.dwj-breadcrumbs')){
    var catEl = document.querySelector('.dwj-post-cat');
    var cat = catEl ? clean(catEl.textContent) : 'Article';

    var crumbs = document.createElement('nav');
    crumbs.className = 'dwj-breadcrumbs';
    crumbs.setAttribute('aria-label','Breadcrumbs');
    crumbs.innerHTML =
      '<a href="/">Home</a><span>›</span>' +
      '<a href="/search/label/'+encodeURIComponent(cat)+'">'+cat+'</a><span>›</span>' +
      '<span>'+clean(postTitle.textContent).slice(0,70)+'</span>';

    postWrap.parentNode.insertBefore(crumbs, postWrap);
  }

  /* TOC */
  var body = document.querySelector('.dwj-post-body');
  if(body && !document.querySelector('.dwj-toc-box')){
    var heads = body.querySelectorAll('h2,h3,h4');
    if(heads.length >= 2){
      var toc = document.createElement('div');
      toc.className = 'dwj-toc-box';

      var list = document.createElement('div');
      list.className = 'dwj-toc-list';

      Array.prototype.forEach.call(heads, function(h, i){
        var id = h.id || 'dwj-section-' + (i+1);
        h.id = id;

        var a = document.createElement('a');
        a.href = '#' + id;
        a.textContent = clean(h.textContent);
        a.className = 'level-' + h.tagName.replace('H','');
        list.appendChild(a);
      });

      toc.innerHTML =
        '<div class="dwj-toc-head">' +
          '<div class="dwj-toc-title">Contents</div>' +
          '<button class="dwj-toc-toggle" type="button" aria-label="Toggle contents">−</button>' +
        '</div>';

      toc.appendChild(list);

      var firstPara = body.querySelector('p');
      if(firstPara){
        firstPara.after(toc);
      }else{
        body.prepend(toc);
      }

      var btn = toc.querySelector('.dwj-toc-toggle');
      btn.addEventListener('click', function(){
        list.classList.toggle('hidden');
        btn.textContent = list.classList.contains('hidden') ? '+' : '−';
      });
    }
  }

  /* Floating Share */
  if(postWrap && !document.querySelector('.dwj-floating-share')){
    var url = encodeURIComponent(location.href);
    var title = encodeURIComponent(document.title);
    var fs = document.createElement('div');
    fs.className = 'dwj-floating-share';
    fs.innerHTML =
      '<a href="https://twitter.com/intent/tweet?url='+url+'&text='+title+'" target="_blank" rel="nofollow noopener">X</a>' +
      '<a href="https://www.linkedin.com/shareArticle?mini=true&url='+url+'&title='+title+'" target="_blank" rel="nofollow noopener">in</a>' +
      '<a href="https://api.whatsapp.com/send?text='+title+'%20'+url+'" target="_blank" rel="nofollow noopener">WA</a>' +
      '<button type="button" id="dwjFloatCopy">⛓</button>';
    document.body.appendChild(fs);

    var copy = document.getElementById('dwjFloatCopy');
    if(copy){
      copy.addEventListener('click', function(){
        navigator.clipboard.writeText(location.href).then(function(){
          copy.textContent = '✓';
          setTimeout(function(){copy.textContent='⛓';}, 1300);
        });
      });
    }
  }

  /* Enhanced meta label */
  var meta = document.querySelector('.dwj-post-meta');
  if(meta && !meta.classList.contains('dwj-meta-enhanced')){
    meta.classList.add('dwj-meta-enhanced');
  }

  /* Popular articles on homepage: clone latest visible post cards where possible */
  var grid = document.getElementById('dwjPopularGrid');
  if(grid){
    function makeCard(card){
      var linkEl = card.matches && card.matches('a') ? card : card.querySelector('a[href]');
      var href = linkEl ? linkEl.href : '#';

      var titleEl = card.querySelector('.dwj-card-title, h3, .post-title, h2, a');
      var title = clean(titleEl ? titleEl.textContent : 'Decode With Jai');

      var imgEl = card.querySelector('img');
      var img = imgEl ? imgEl.src : '';

      var catEl = card.querySelector('.dwj-card-cat, .post-cat');
      var cat = clean(catEl ? catEl.textContent : 'Article');

      return '<a class="dwj-popular-card" href="'+href+'">' +
        '<div class="dwj-popular-thumb">'+(img ? '<img alt="'+title.replace(/"/g,'&quot;')+'" loading="lazy" src="'+img+'"/>' : '🔥')+'</div>' +
        '<div class="dwj-popular-body">' +
          '<div class="dwj-popular-cat">'+cat+'</div>' +
          '<h3>'+title+'</h3>' +
          '<div class="dwj-popular-meta">Popular Read →</div>' +
        '</div>' +
      '</a>';
    }

    setTimeout(function(){
      var cards = Array.prototype.slice.call(document.querySelectorAll('.dwj-card, .post, article'));
      cards = cards.filter(function(c){
        return !c.closest('#popular-articles') && !c.closest('#dwjFeaturedBox') && c.querySelector('a[href]');
      }).slice(0,6);

      if(cards.length){
        grid.innerHTML = cards.map(makeCard).join('');
      }else{
        grid.innerHTML = '<div class="dwj-featured-empty">Popular articles will appear after posts load.</div>';
      }
    }, 1200);
  }
})();
