(function(){
  function esc(s){
    return String(s || '').replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }
  function clean(s){
    return String(s || '').replace(/\s+/g,' ').trim();
  }
  function getUrl(e){
    if(!e.link) return '#';
    for(var i=0;i<e.link.length;i++){
      if(e.link[i].rel === 'alternate') return e.link[i].href;
    }
    return '#';
  }
  function getThumb(e){
    function up(u){
      return String(u || '')
        .replace(/\/s72-c\//, '/s1200/')
        .replace(/\/s\d+(-c)?\//, '/s1200/')
        .replace(/=s\d+(-c)?/g, '=s1200')
        .replace(/=w\d+-h\d+(-p-k-no-nu)?/g, '=w1200-h675-p-k-no-nu');
    }
    if(e.content && e.content.$t){
      var m = e.content.$t.match(/<img[^>]+src=["']([^"']+)["']/i);
      if(m) return up(m[1]);
    }
    if(e.media$thumbnail && e.media$thumbnail.url){
      return up(e.media$thumbnail.url);
    }
    return '';
  }
  function getCat(e){
    return (e.category && e.category[0]) ? e.category[0].term : 'Article';
  }
  function getSnippet(e){
    var raw = '';
    if(e.summary && e.summary.$t) raw = e.summary.$t;
    else if(e.content && e.content.$t){
      var div = document.createElement('div');
      div.innerHTML = e.content.$t;
      raw = div.textContent || div.innerText || '';
    }
    raw = clean(raw);
    return raw.slice(0,150) + (raw.length > 150 ? '...' : '');
  }
  function cardHTML(e){
    var title = e.title && e.title.$t ? e.title.$t : 'Decode With Jai';
    var url = getUrl(e);
    var img = getThumb(e);
    var cat = getCat(e);
    var snip = getSnippet(e);
    return '<article class="dwj-card">' +
      '<a class="dwj-card-media" href="'+esc(url)+'">' +
        (img ? '<img alt="'+esc(title)+'" loading="lazy" src="'+esc(img)+'"/>' : '<div class="dwj-card-ph">📝</div>') +
      '</a>' +
      '<div class="dwj-card-body">' +
        '<div class="dwj-card-cat">'+esc(cat)+'</div>' +
        '<h3 class="dwj-card-title"><a href="'+esc(url)+'">'+esc(title)+'</a></h3>' +
        '<p class="dwj-card-snip">'+esc(snip)+'</p>' +
        '<div class="dwj-card-date">Read Article →</div>' +
      '</div>' +
    '</article>';
  }

  /* Fix /search and /search/label pages */
  window.dwjArchiveFeedOverride = function(data){
    var grid = document.querySelector('.dwj-posts-grid');
    if(!grid) return;

    var entries = data && data.feed && data.feed.entry ? data.feed.entry : [];
    if(!entries.length){
      grid.innerHTML = '<div class="dwj-archive-feed-note">No posts found in this archive.</div>';
      return;
    }

    grid.innerHTML = entries.map(cardHTML).join('');

    var title = document.querySelector('#latest .dwj-title');
    if(title && location.pathname === '/search'){
      title.textContent = 'All Articles';
    }

    var pagination = document.querySelector('.dwj-pagination');
    if(pagination) pagination.style.display = 'none';
  };

  function loadArchiveIfNeeded(){
    var isSearch = location.pathname.indexOf('/search') === 0;
    if(!isSearch) return;

    var grid = document.querySelector('.dwj-posts-grid');
    if(!grid) return;

    grid.innerHTML = '<div class="dwj-archive-feed-note">Loading all articles...</div>';

    var feed = '/feeds/posts/summary';
    var labelMatch = location.pathname.match(/\/search\/label\/([^\/?#]+)/);
    if(labelMatch && labelMatch[1]){
      var label = decodeURIComponent(labelMatch[1]);
      feed = '/feeds/posts/summary/-/' + encodeURIComponent(label);
    }

    var s = document.createElement('script');
    s.src = feed + '?alt=json-in-script&max-results=50&callback=dwjArchiveFeedOverride';
    s.onerror = function(){
      grid.innerHTML = '<div class="dwj-archive-feed-note">Could not load archive feed.</div>';
    };
    document.head.appendChild(s);
  }

  /* Fix homepage Popular Articles */
  window.dwjPopularFeedOverride = function(data){
    var grid = document.getElementById('dwjPopularGrid');
    if(!grid) return;

    var entries = data && data.feed && data.feed.entry ? data.feed.entry : [];
    if(!entries.length){
      grid.innerHTML = '<div class="dwj-featured-empty">No posts found yet.</div>';
      return;
    }

    grid.innerHTML = entries.slice(0,6).map(function(e){
      var title = e.title && e.title.$t ? e.title.$t : 'Decode With Jai';
      var url = getUrl(e);
      var img = getThumb(e);
      var cat = getCat(e);
      return '<a class="dwj-popular-card" href="'+esc(url)+'">' +
        '<div class="dwj-popular-thumb">'+(img ? '<img alt="'+esc(title)+'" loading="lazy" src="'+esc(img)+'"/>' : '🔥')+'</div>' +
        '<div class="dwj-popular-body">' +
          '<div class="dwj-popular-cat">'+esc(cat)+'</div>' +
          '<h3>'+esc(title)+'</h3>' +
          '<div class="dwj-popular-meta">Popular / Latest →</div>' +
        '</div>' +
      '</a>';
    }).join('');
  };

  function loadPopularIfNeeded(){
    var grid = document.getElementById('dwjPopularGrid');
    if(!grid) return;
    grid.innerHTML = '<div class="dwj-featured-loading">Loading popular articles...</div>';

    var s = document.createElement('script');
    s.src = '/feeds/posts/summary?alt=json-in-script&max-results=6&callback=dwjPopularFeedOverride';
    s.onerror = function(){
      grid.innerHTML = '<div class="dwj-featured-empty">Popular articles could not load.</div>';
    };
    document.head.appendChild(s);
  }

  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', function(){
      loadArchiveIfNeeded();
      loadPopularIfNeeded();
    });
  }else{
    loadArchiveIfNeeded();
    loadPopularIfNeeded();
  }
})();
