(function(){
  // Upgrade Blogger image URLs to larger sizes for archive cards
  function bigImg(url){
    if(!url) return '';
    return String(url)
      .replace(/\/s72-c\//, '/s1200/')
      .replace(/\/s1600\//, '/s1200/')
      .replace(/\/s\d+(-c)?\//, '/s1200/')
      .replace(/=s\d+(-c)?/g, '=s1200')
      .replace(/=w\d+-h\d+(-p-k-no-nu)?/g, '=w1200-h675-p-k-no-nu');
  }

  function fixCardImages(){
    var cards = document.querySelectorAll('.dwj-card');
    cards.forEach(function(card){
      var media = card.querySelector('.dwj-card-media');
      if(!media) return;

      var img = media.querySelector('img');
      if(img){
        var src = img.getAttribute('src') || img.getAttribute('data-src') || '';
        img.src = bigImg(src);
        img.removeAttribute('width');
        img.removeAttribute('height');
        img.style.width = '100%';
        img.style.height = '100%';
        img.style.objectFit = 'cover';
        img.style.objectPosition = 'center';
        return;
      }

      // If no image exists, try to find an image from snippet/body text if available
      var bodyImg = card.querySelector('.dwj-card-body img');
      if(bodyImg && bodyImg.src){
        media.innerHTML = '<img loading="lazy" src="'+bigImg(bodyImg.src)+'" alt="Decode With Jai"/>';
      }
    });
  }

  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', fixCardImages);
  }else{
    fixCardImages();
  }

  setTimeout(fixCardImages, 1000);
  setTimeout(fixCardImages, 2500);
})();
