(function(){
  function fixEmptyAds(){
    document.querySelectorAll('.dwj-ad-inarticle').forEach(function(ad){
      var hasRealContent = ad.querySelector('ins, iframe, img, script') || ad.textContent.trim().length > 5;
      if(hasRealContent){
        ad.classList.add('has-ad');
      }else{
        ad.style.display = 'none';
        ad.style.minHeight = '0';
        ad.style.padding = '0';
        ad.style.margin = '0';
        ad.style.border = '0';
      }
    });
  }
  if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', fixEmptyAds);
  else fixEmptyAds();
  setTimeout(fixEmptyAds, 1200);
})();
